// German v2 Unit 18 — Arabic source language (srcLang:"ar")
// Auto-generated. Fields marked [AR] need manual Arabic translation.
const UNIT_18_AR = {n:18,lang:"de",srcLang:"ar",track:"v2",title:"Im Biergarten",sub:"Beer garden, Spargelzeit, als vs wenn, fixed prepositions, da-/wo- compounds",icon:"🍺",level:"B1.2",color:"#7B5EE8",lessons:[
    {id:"deu_r18l1",title:"Unter den Kastanien",icon:"🌳",xp:15,board:true,steps:[
        {type:"intro",title:"Unter den Kastanien",desc:"حديقة بيرة في برلين في أواخر يونيو. ضوء ذهبي عبر أوراق الكستناء. أضواء زينة، نقانق مشوية، قرع أكواب البيرة. حان الوقت لتعلم كيف يتواصل الألمان في الهواء الطلق.",goals:[
            "تعلّم 18 كلمة عن المطاعم والتواصل الاجتماعي",
            "تعرّف على الطاقم الكامل لأمسية صيفية معاً",
            "عبّر عن الجوع والعطش والرضا"
          ]},
        {type:"story",speaker:"narrator",mood:"warm",art:"de-ber-biergarten-entrance",trg:"Ein Berliner Biergarten im späten Juni. Goldenes Licht fällt durch die Blätter der Kastanienbäume. Lichterketten leuchten schon. Lange Holzbänke, der Geruch von gegrillten Würstchen, das Klirren von Bierkrügen. Hildi sitzt an einem reservierten Tisch, die Arme verschränkt, und beobachtet den Eingang.",src:"حديقة بيرة في برلين في أواخر يونيو. ضوء ذهبي يتساقط عبر أوراق أشجار الكستناء. أضواء الزينة متوهجة بالفعل. مقاعد خشبية طويلة، رائحة النقانق المشوية، قرع أكواب البيرة. هيلدي تجلس على طاولة محجوزة، ذراعاها متقاطعتان، تراقب المدخل."},
        {type:"story",speaker:"hildi",mood:"pleased",art:"de-ber-biergarten-table",trg:"Hier! Ich habe den besten Tisch reserviert. Unter den alten Kastanien. Als ich jung war, gab es hier nur drei Biergärten in ganz Berlin.",src:"هنا! حجزت أفضل طاولة. تحت أشجار الكستناء القديمة. عندما كنت شابة، لم يكن هناك سوى ثلاث حدائق بيرة في كل برلين."},
        {type:"story",speaker:"verumius",mood:"happy",trg:"Es ist wunderschön hier. So gemütlich. Ich freue mich auf den Abend.",src:"إنه جميل هنا. مريح جداً. أتطلع إلى هذه الأمسية."},
        {type:"story",speaker:"mia",mood:"energetic",trg:"Entschuldigung, ich komme direkt vom Lauftreff. Ich bin so durstig! Und hungrig. Beides.",src:"آسف، أنا قادم مباشرة من مجموعة الركض. أنا عطشان جداً! وجائع. كلاهما."},
        {type:"story",speaker:"narrator",mood:"curious",trg:"Lukas kommt als Letzter. Er trägt etwas Ungewöhnliches auf dem Rücken: einen Gitarrenkoffer. Niemand sagt etwas, aber Mia hebt eine Augenbraue.",src:"لوكاس يصل أخيراً. يحمل شيئاً غير عادي على ظهره: حقيبة غيتار. لا أحد يقول شيئاً، لكن ميا ترفع حاجباً."},
        {type:"teach",trg:"die Terrasse",src:"الشرفة، التراس",pos:"noun",gender:"f",note:"منطقة طعام خارجية. حدائق البيرة لها تقاليدها الخاصة، لكن كلاهما يعني الأكل في الخارج.",example:"A: Sollen wir drinnen oder auf der Terrasse sitzen?\nB: Auf der Terrasse! Das Wetter ist perfekt.\nA: Gut, ich sehe noch einen freien Tisch.\nB: Schnell, bevor ihn jemand nimmt!",exampleSrc:"A: هل نجلس في الداخل أم على الشرفة؟\nB: على الشرفة! الطقس مثالي.\nA: جيد، أرى طاولة فارغة.\nB: بسرعة، قبل أن يأخذها أحد!",funFact:"من الفرنسية 'terrasse'. الألمان يتدفقون إلى الخارج لحظة ظهور الشمس. حدائق البيرة لها تقاليدها المنفصلة عن التراس، لكن كلاهما يعني الأكل في الخارج."},
        {type:"teach",trg:"der Treffpunkt",src:"نقطة الالتقاء",pos:"noun",gender:"m",note:"'Treff' (لقاء) + 'Punkt' (نقطة). كل مجموعة أصدقاء لها واحدة.",example:"A: Wo ist unser Treffpunkt heute?\nB: Im Biergarten, unter den Kastanien.\nA: Gut, ich bin in zehn Minuten da.\nB: Hildi wartet schon!",exampleSrc:"A: أين نقطة لقائنا اليوم؟\nB: في حديقة البيرة، تحت أشجار الكستناء.\nA: جيد، سأكون هناك خلال عشر دقائق.\nB: هيلدي تنتظر بالفعل!",funFact:"'Treff' (لقاء) + 'Punkt' (نقطة). كل مجموعة أصدقاء ألمانية لها نقطة لقائها Treffpunkt. حديقة البيرة في الصيف هي الأمثل."},
        {type:"teach",trg:"der Wirt",src:"صاحب الحانة",pos:"noun",gender:"m",note:"من الألمانية القديمة العليا 'wirt' (مضيف). يدير عملية حديقة البيرة بأكملها.",example:"A: Wer ist der Wirt hier?\nB: Der Mann mit der Schürze da drüben.\nA: Er sieht freundlich aus.\nB: Ja, er kennt alle Stammgäste beim Namen.",exampleSrc:"A: من صاحب الحانة هنا؟\nB: الرجل ذو المئزر هناك.\nA: يبدو ودوداً.\nB: نعم، يعرف كل الزبائن الدائمين بالاسم.",funFact:"صاحب الحانة. من الألمانية القديمة العليا 'wirt' (مضيف). يدير صاحب حديقة البيرة العملية بأكملها. مرتبط بالإنجليزية 'worth' من خلال فكرة الضيافة."},
        {type:"teach",trg:"die Wirtin",src:"صاحبة الحانة",pos:"noun",gender:"f",note:"لاحقة -in تدل على المؤنث. كثير من صاحبات الحانات الشهيرات في برلين أدرن حدائق بيرة أسطورية.",example:"A: Die Wirtin hat uns begrüßt.\nB: Ja, sie ist hier seit zwanzig Jahren.\nA: Sie kennt wirklich jeden.\nB: Das macht einen guten Biergarten aus.",exampleSrc:"A: صاحبة الحانة رحّبت بنا.\nB: نعم، هي هنا منذ عشرين عاماً.\nA: هي حقاً تعرف الجميع.\nB: هذا ما يصنع حديقة بيرة جيدة.",funFact:"صاحبة الحانة. لاحقة -in. كثير من صاحبات الحانات الشهيرات في برلين أدرن حدائق بيرة أسطورية لعقود. 'Die Wirtin' أيضاً عنوان أغنية شعبية ألمانية مشهورة."},
        {type:"teach",trg:"der Kellner",src:"النادل",pos:"noun",gender:"m",note:"من 'Keller' (قبو). كان في الأصل الشخص الذي يحضر المشروبات من القبو.",example:"A: Wo ist unser Kellner?\nB: Ich glaube, er bedient den Tisch da drüben.\nA: Wir warten schon zehn Minuten.\nB: Im Biergarten muss man geduldig sein.",exampleSrc:"A: أين النادل؟\nB: أعتقد أنه يخدم الطاولة هناك.\nA: ننتظر منذ عشر دقائق.\nB: في حديقة البيرة يجب أن تكون صبوراً.",funFact:"من 'Keller' (قبو). النادل كان في الأصل الشخص الذي يحضر المشروبات من القبو. في بافاريا، قد تسمع 'Bedienung!' (خدمة!) بدلاً من مناداة النادل."},
        {type:"teach",trg:"die Kellnerin",src:"النادلة",pos:"noun",gender:"f",note:"نادلة. في حديقة بيرة تقليدية، تحمل عدة أكواب بيرة سعة لتر واحد دفعة واحدة.",example:"A: Die Kellnerin ist unglaublich schnell.\nB: Siehst du, wie viele Bierkrüge sie trägt?\nA: Vier auf einmal!\nB: Das ist noch gar nichts für einen Biergarten.",exampleSrc:"A: النادلة سريعة بشكل لا يُصدّق.\nB: هل ترى كم كوب بيرة تحمل؟\nA: أربعة دفعة واحدة!\nB: هذا لا شيء لحديقة بيرة.",funFact:"نادلة. في حديقة بيرة تقليدية، تحمل النادلة عدة أكواب بيرة سعة لتر دفعة واحدة. الرقم القياسي 29 كوباً حملتها نادلة بافارية دفعة واحدة."},
        {type:"teach",trg:"der Ober",src:"النادل (رسمي)",pos:"noun",gender:"m",note:"اختصار لـ 'Oberkellner' (رئيس النُدُل). كلمة أقدم وأكثر رسمية.",example:"A: Herr Ober, die Speisekarte bitte!\nB: Sofort, mein Herr.\nA: Und bringen Sie bitte auch Wasser.\nB: Natürlich, stilles oder mit Kohlensäure?",exampleSrc:"A: يا نادل، القائمة من فضلك!\nB: حالاً، سيدي.\nA: ومن فضلك أحضر ماءً أيضاً.\nB: بالطبع، عادي أم فوّار؟",funFact:"اختصار لـ 'Oberkellner' (رئيس النُدُل). كلمة أقدم وأكثر رسمية. 'Herr Ober!' هي طريقة مناداة النادل في مطعم نمساوي أو جنوب ألماني تقليدي."},
        {type:"teach",trg:"das Trinkgeld",src:"البقشيش",pos:"noun",gender:"n",note:"'Trink' (شرب) + 'Geld' (مال). في ألمانيا، البقشيش 5-10%.",example:"A: Wie viel Trinkgeld gibt man in Deutschland?\nB: Normalerweise fünf bis zehn Prozent.\nA: Das ist weniger als in Amerika.\nB: Ja, aber Kellner verdienen hier mehr Grundgehalt.",exampleSrc:"A: كم بقشيش تعطي في ألمانيا؟\nB: عادة خمسة إلى عشرة بالمئة.\nA: هذا أقل من أمريكا.\nB: نعم، لكن النُدُل يكسبون راتباً أساسياً أعلى هنا.",funFact:"'Trink' (شرب) + 'Geld' (مال). مال البقشيش كان أصلاً مالاً ليشتري النادل لنفسه مشروباً. في ألمانيا، البقشيش 5-10%، وليس 15-20% الشائعة في أمريكا."},
        {type:"teach",trg:"der Grill",src:"الشواية، الباربكيو",pos:"noun",gender:"m",note:"نفس الكلمة بالإنجليزية. الألمان يشوون بهوس في الصيف.",example:"A: Riechst du den Grill?\nB: Ja, Bratwurst und Steaks!\nA: Ich will auch etwas vom Grill.\nB: Dann gehen wir zur Grillstation.",exampleSrc:"A: هل تشم رائحة الشواية؟\nB: نعم، نقانق وستيك!\nA: أريد شيئاً من الشواية أيضاً.\nB: إذن لنذهب إلى محطة الشواء.",funFact:"نفس الكلمة بالإنجليزية. الألمان يشوون بهوس في الصيف. 'Grillen' (الشواء) هو عملياً رياضة وطنية. حديقة البيرة غالباً فيها محطة شواء بالنقانق والستيك."},
        {type:"teach",trg:"die Scheibe",src:"الشريحة، القرص",pos:"noun",gender:"f",note:"أي شيء مسطح ودائري أو مسطح ورقيق. 'Eine Scheibe Brot' = شريحة خبز.",example:"A: Möchtest du eine Scheibe Brot?\nB: Ja, bitte, mit Butter.\nA: Und eine Scheibe Käse dazu?\nB: Perfekt, danke!",exampleSrc:"A: هل تريد شريحة خبز؟\nB: نعم من فضلك، مع زبدة.\nA: وشريحة جبن معها؟\nB: ممتاز، شكراً!",funFact:"شريحة أو قرص أو لوح. 'Eine Scheibe Brot' (شريحة خبز). أيضاً 'Windschutzscheibe' (الزجاج الأمامي). الكلمة تغطي أي شيء مسطح ودائري أو مسطح ورقيق."},
        {type:"teach",trg:"die Mahlzeit",src:"الوجبة، وقت الوجبة",pos:"noun",gender:"f",note:"'Mahl' (وجبة) + 'Zeit' (وقت). أيضاً تحية ظهيرة بين الزملاء.",example:"A: Mahlzeit!\nB: Mahlzeit! Gehst du auch in die Kantine?\nA: Ja, ich brauche eine warme Mahlzeit.\nB: Ich auch. Heute gibt es Schnitzel.",exampleSrc:"A: بالعافية! (تحية الظهيرة)\nB: بالعافية! هل تذهب إلى الكافتيريا أيضاً؟\nA: نعم، أحتاج وجبة ساخنة.\nB: وأنا أيضاً. اليوم لديهم شنيتزل.",funFact:"'Mahl' (وجبة) + 'Zeit' (وقت). أيضاً تحية: قول 'Mahlzeit!' عند الظهيرة هو كيف يحيي الزملاء الألمان بعضهم عند الغداء. هي كلمة وطقس اجتماعي في آنٍ واحد."},
        {type:"teach",trg:"gemütlich",src:"مريح، دافئ، ودّي",pos:"adj",gender:null,note:"ربما أكثر كلمة ألمانية يصعب ترجمتها. لا توجد كلمة إنجليزية واحدة تعبّر عنها.",example:"A: Der Biergarten ist wirklich gemütlich.\nB: Ja, die Lichterketten machen alles so schön.\nA: Und die alten Kastanienbäume.\nB: Das ist typisch deutsch: Gemütlichkeit im Freien.",exampleSrc:"A: حديقة البيرة مريحة حقاً.\nB: نعم، أضواء الزينة تجعل كل شيء جميلاً.\nA: وأشجار الكستناء القديمة.\nB: هذا ألماني تقليدي: الراحة في الهواء الطلق.",funFact:"ربما أكثر كلمة ألمانية يصعب ترجمتها. مريح، ودّي، دافئ، مسترخٍ. حديقة بيرة تحت أشجار الكستناء في أمسية صيفية هي تعريف gemütlich. لا توجد كلمة إنجليزية واحدة تعبّر عنها."},
        {type:"teach",trg:"durstig",src:"عطشان",pos:"adj",gender:null,note:"من 'Durst' (عطش). لاحقة -ig تحوّل الأسماء إلى صفات.",example:"A: Bist du durstig?\nB: Ja, sehr! Ich brauche ein großes Bier.\nA: Oder ein Wasser?\nB: Erst das Bier, dann das Wasser.",exampleSrc:"A: هل أنت عطشان؟\nB: نعم، جداً! أحتاج بيرة كبيرة.\nA: أو ماء؟\nB: أولاً البيرة، ثم الماء.",funFact:"من 'Durst' (عطش). 'Ich bin durstig' هي مفردات البقاء في أي حديقة بيرة. لاحقة -ig تحوّل الأسماء إلى صفات: Durst تصبح durstig، Hunger تصبح hungrig."},
        {type:"teach",trg:"hungrig",src:"جائع",pos:"adj",gender:null,note:"من 'Hunger'. نفس النمط مثل durstig. مشتركة الأصل مع الإنجليزية 'hungry'.",example:"A: Ich bin so hungrig!\nB: Wollen wir etwas bestellen?\nA: Ja, sofort. Eine Bratwurst vom Grill.\nB: Und Kartoffelsalat dazu.",exampleSrc:"A: أنا جائع جداً!\nB: هل نطلب شيئاً؟\nA: نعم، فوراً. نقانق من الشواية.\nB: وسلطة بطاطس معها.",funFact:"من 'Hunger'. نفس النمط مثل durstig. 'Bist du hungrig?' هو السؤال الذي يبدأ كل أمسية في حديقة البيرة. مشتركة الأصل مع الإنجليزية 'hungry'."},
        {type:"teach",trg:"satt",src:"شبعان، مُكتفٍ (بعد الأكل)",pos:"adj",gender:null,note:"'Ich bin satt' = لقد اكتفيت. عكس hungrig.",example:"A: Möchtest du noch etwas?\nB: Nein danke, ich bin satt.\nA: Wirklich? Es gibt noch Kuchen.\nB: Na gut, ein kleines Stück vielleicht.",exampleSrc:"A: هل تريد المزيد؟\nB: لا شكراً، أنا شبعان.\nA: حقاً؟ لا يزال هناك كعك.\nB: حسناً، قطعة صغيرة ربما.",funFact:"شبعان، مُكتفٍ (بعد الأكل). 'Ich bin satt' تعني أنك اكتفيت. الألمان يقولون 'satt' وليس 'voll' للشبع. 'Voll' تعني سكران."},
        {type:"teach",trg:"genießen",src:"يستمتع، يتذوق",pos:"verb",gender:null,note:"فعل قوي غير منتظم (genoss، genossen). 'Genieße den Abend!'",example:"A: Genießt du den Abend?\nB: Ja, sehr! Das Essen ist toll.\nA: Und die Musik erst!\nB: Ich genieße jeden Moment.",exampleSrc:"A: هل تستمتع بالأمسية؟\nB: نعم، كثيراً! الطعام رائع.\nA: والموسيقى!\nB: أستمتع بكل لحظة.",funFact:"يستمتع، يتذوق. فعل قوي غير منتظم (genoss، genossen). من نفس جذر 'Genuss' (متعة/استمتاع). كلمة للاستمتاع الواعي والمتعمد."},
        {type:"teach",trg:"spazieren gehen",src:"يتمشى",pos:"verb",gender:null,note:"عبارة فعلية منفصلة. 'Wir gehen spazieren.' من الإيطالية 'spaziare'.",example:"A: Wollen wir nach dem Essen spazieren gehen?\nB: Gute Idee! Durch den Park.\nA: Der Abend ist so schön.\nB: Ja, ein Spaziergang nach dem Essen ist gesund.",exampleSrc:"A: هل نتمشى بعد العشاء؟\nB: فكرة جيدة! عبر الحديقة.\nA: الأمسية جميلة جداً.\nB: نعم، المشي بعد العشاء صحي.",funFact:"عبارة فعلية منفصلة. من الإيطالية 'spaziare' (يأخذ مساحة). نزهة المساء الألمانية (Spaziergang) هي مؤسسة ثقافية."},
        {type:"teach",trg:"prost",src:"في صحتك",pos:"intj",gender:null,note:"من اللاتينية 'prosit' (ليكن نافعاً). يجب أن تنظر في العيون عند قرع الكؤوس.",example:"A: Prost!\nB: Prost! Auf einen schönen Abend!\nA: Vergiss nicht: Augenkontakt!\nB: Stimmt, sonst gibt es sieben Jahre Pech.",exampleSrc:"A: في صحتك!\nB: في صحتك! لأمسية جميلة!\nA: لا تنسَ: النظر في العيون!\nB: صحيح، وإلا سبع سنوات من سوء الحظ.",funFact:"من اللاتينية 'prosit' (ليكن نافعاً). النخب الألماني العالمي. يجب أن تنظر في العيون عند قرع الكؤوس. عدم فعل ذلك يجلب سبع سنوات من سوء الحظ حسب الاعتقاد."},
        {type:"mc",q:"Mia kommt vom Lauftreff und sagt, sie ist sehr ___. Welches Wort beschreibt ihren Zustand?",opts:["satt","gemütlich","durstig","hungrig"],ans:"durstig",hint:"تريد شيئاً للشرب أولاً. هذه الكلمة مشتقة من Durst."},
        {type:"mc",q:"Was bedeutet 'Mahlzeit!', wenn ein Kollege es um die Mittagszeit sagt?",opts:["Es bedeutet Tschüss","Es ist eine Entschuldigung","Es bedeutet Danke","Es ist ein Mittagsgruß"],ans:"Es ist ein Mittagsgruß",hint:"Mahl تعني وجبة، Zeit تعني وقت. فكّر فيما يحدث عند الظهيرة في المكاتب الألمانية."},
        {type:"fb",s:"Lukas, möchtest du etwas trinken? -- Ja, ich bin sehr {1}!",a:["durstig"],opts:["durstig","hungrig","satt","gemütlich"],hint:"لوكاس يريد شيئاً للشرب. أي صفة تصف العطش؟",sSrc:"لوكاس، هل تريد شيئاً للشرب؟ -- نعم، أنا عطشان جداً!"}
      ]},
    {id:"deu_r18l2",title:"Brotzeit und Bratwurst",icon:"🍔",xp:15,board:true,steps:[
        {type:"intro",title:"Brotzeit und Bratwurst",desc:"حان وقت ملء الطاولة. تعلّم أدوات المطبخ والمكونات وحالات الطعام. من المقلاة إلى البرقوق، من النيء إلى المطبوخ.",goals:[
            "سمِّ أدوات المطبخ وأواني الطهي",
            "صِف المكونات وخصائصها",
            "ميّز بين حالات الطعام النيء والمطبوخ"
          ]},
        {type:"story",speaker:"hildi",mood:"commanding",art:"de-ber-biergarten-menu",trg:"So. Jetzt wird bestellt. Die Karte ist lang, aber ich empfehle die Brotzeit. Und Bratwurst vom Grill. Wer etwas anderes will, muss schnell sein. Der Kellner kommt gleich.",src:"حسناً. الآن نطلب. القائمة طويلة، لكن أنصح بالبروتزايت. ونقانق من الشواية. من يريد شيئاً آخر يجب أن يكون سريعاً. النادل قادم."},
        {type:"teach",trg:"die Pfanne",src:"المقلاة",pos:"noun",gender:"f",note:"من اللاتينية 'patina'. 'Bratpfanne' (مقلاة القلي) هي حيث تحصل النقانق على أزيزها.",example:"A: Wo ist die Pfanne?\nB: Im Schrank, neben dem Herd.\nA: Ich brauche die große Bratpfanne.\nB: Die mit dem schwarzen Griff?",exampleSrc:"A: أين المقلاة؟\nB: في الخزانة، بجانب الموقد.\nA: أحتاج المقلاة الكبيرة.\nB: تلك ذات المقبض الأسود؟",funFact:"من اللاتينية 'patina'. 'Bratpfanne' (مقلاة القلي) هي حيث تحصل النقانق على أزيزها. 'Etwas auf die Pfanne hauen' (يضرب شيئاً على المقلاة) عامية لفعل شيء بجرأة."},
        {type:"teach",trg:"die Kanne",src:"الإبريق",pos:"noun",gender:"f",note:"'Kaffeekanne' (إبريق قهوة)، 'Teekanne' (إبريق شاي)، 'Gießkanne' (إبريق سقي).",example:"A: Soll ich eine Kanne Kaffee machen?\nB: Ja, bitte! Eine große Kanne.\nA: Mit Milch?\nB: Nein, schwarz.",exampleSrc:"A: هل أصنع إبريق قهوة؟\nB: نعم، من فضلك! إبريق كبير.\nA: مع حليب؟\nB: لا، أسود.",funFact:"إبريق أو وعاء. 'Kaffeekanne' (إبريق قهوة)، 'Teekanne' (إبريق شاي)، 'Gießkanne' (إبريق سقي). مركبات -kanne تغطي كل نوع من أوعية السكب."},
        {type:"teach",trg:"die Schüssel",src:"الوعاء",pos:"noun",gender:"f",note:"من 'schütten' (يسكب). لا تخلطها مع 'Schlüssel' (مفتاح).",example:"A: Gib mir bitte die große Schüssel.\nB: Für den Kartoffelsalat?\nA: Ja, wir brauchen viel Platz.\nB: Hier, die reicht bestimmt.",exampleSrc:"A: من فضلك أعطني الوعاء الكبير.\nB: لسلطة البطاطس؟\nA: نعم، نحتاج مساحة كبيرة.\nB: تفضل، هذا يكفي.",funFact:"من 'schütten' (يسكب). الوعاء يحمل السلطات أو الشوربة أو سلطة البطاطس في حديقة البيرة. لا تخلطها مع 'Schlüssel' (مفتاح). حرف واحد فرق، أشياء مختلفة تماماً."},
        {type:"teach",trg:"die Dose",src:"العلبة",pos:"noun",gender:"f",note:"'Konservendose' (طعام معلب). 'Dosenbier' (بيرة معلبة) هي الخيار الاقتصادي.",example:"A: Hast du eine Dose Tomaten?\nB: Ja, im Regal oben.\nA: Und Dosenbier?\nB: Im Kühlschrank, ganz unten.",exampleSrc:"A: هل لديك علبة طماطم؟\nB: نعم، على الرف العلوي.\nA: وبيرة معلبة؟\nB: في الثلاجة، في الأسفل تماماً.",funFact:"علبة. 'Konservendose' (طعام معلب). في مناطق ألمانية كثيرة، Dose تعني أيضاً حاوية صغيرة أو صندوق. 'Dosenbier' (بيرة معلبة) هي الخيار الاقتصادي في أي تجمع في حديقة ألمانية."},
        {type:"teach",trg:"die Tüte",src:"الكيس (ورقي أو بلاستيكي)",pos:"noun",gender:"f",note:"'Eine Tüte Chips' (كيس رقائق). في جنوب ألمانيا: 'Sackerl' أو 'Sack'.",example:"A: Brauchen Sie eine Tüte?\nB: Nein danke, ich habe meinen Beutel.\nA: In Berlin sagt man Tüte, in München Sackerl.\nB: Und in der Schweiz?",exampleSrc:"A: هل تحتاج كيساً؟\nB: لا شكراً، لدي كيسي الخاص.\nA: في برلين يقولون Tüte، في ميونيخ Sackerl.\nB: وفي سويسرا؟",funFact:"كيس (ورقي أو بلاستيكي). في شمال ألمانيا، Tüte عالمية. في جنوب ألمانيا والنمسا، يقولون 'Sackerl' أو 'Sack'. المفردات الإقليمية في أبهى صورها."},
        {type:"teach",trg:"die Zutat",src:"المكوّن",pos:"noun",gender:"f",note:"'Zu' (إلى/مُضاف) + 'Tat' (فعل). شيء 'مُضاف إلى فعل' الطهي.",example:"A: Welche Zutaten brauchen wir?\nB: Mehl, Eier und Zucker.\nA: Haben wir alles?\nB: Wir brauchen noch Butter.",exampleSrc:"A: أي مكونات نحتاج؟\nB: طحين وبيض وسكر.\nA: هل لدينا كل شيء؟\nB: لا نزال نحتاج زبدة.",funFact:"'Zu' (إلى/مُضاف) + 'Tat' (فعل). مكوّن، حرفياً شيء 'مُضاف إلى فعل' الطهي. 'Zutaten' (جمع) هي ما تسرده كل وصفة أولاً."},
        {type:"teach",trg:"die Zwiebel",src:"البصل",pos:"noun",gender:"f",note:"من اللاتينية 'cepulla' (بصلة صغيرة). في كل طبق ألماني تقريباً.",example:"A: Kannst du die Zwiebeln schneiden?\nB: Ja, aber ich weine immer dabei.\nA: Versuch es mit einer Taucherbrille.\nB: Das ist nicht dein Ernst!",exampleSrc:"A: هل تستطيع تقطيع البصل؟\nB: نعم، لكنني أبكي دائماً عند ذلك.\nA: جرّب ارتداء نظارات سباحة.\nB: لست جاداً!",funFact:"من اللاتينية 'cepulla' (بصلة صغيرة). البصل في كل طبق ألماني تقريباً. 'Zwiebelkuchen' (فطيرة البصل) مع Federweißer (نبيذ شاب) هي تقليد خريفي."},
        {type:"teach",trg:"der Pfeffer",src:"الفلفل",pos:"noun",gender:"m",note:"من اللاتينية 'piper' التي جاءت من السنسكريتية. نفس الجذر مثل الإنجليزية 'pepper'.",example:"A: Kannst du mir den Pfeffer geben?\nB: Hier, bitte. Schwarzer oder weißer?\nA: Schwarzer Pfeffer, frisch gemahlen.\nB: Das macht alles besser.",exampleSrc:"A: هل تناولني الفلفل؟\nB: تفضل. أسود أم أبيض؟\nA: فلفل أسود، مطحون طازجاً.\nB: هذا يجعل كل شيء أفضل.",funFact:"من اللاتينية 'piper' التي جاءت من السنسكريتية. 'Geh dahin, wo der Pfeffer wächst!' (اذهب حيث ينمو الفلفل!) تعني 'اذهب بعيداً!' لأن الفلفل كان يأتي من بعيد."},
        {type:"teach",trg:"das Mehl",src:"الطحين",pos:"noun",gender:"n",note:"من الألمانية القديمة العليا 'melo' (حبوب مطحونة). مرتبط بالإنجليزية 'meal' و'mill'.",example:"A: Wie viel Mehl brauchen wir?\nB: Zweihundert Gramm Mehl Typ 405.\nA: Was bedeutet 405?\nB: Das ist besonders feines Mehl zum Backen.",exampleSrc:"A: كم طحين نحتاج؟\nB: مئتا غرام من طحين نوع 405.\nA: ماذا يعني 405؟\nB: هذا طحين ناعم جداً للخبز.",funFact:"من الألمانية القديمة العليا 'melo' (حبوب مطحونة). مرتبط بالإنجليزية 'meal' (حبوب مطحونة) و'mill'. الخبز الألماني يعتمد على أنواع دقيقة من الطحين: نوع 405 (ناعم)، 550، 1050 (خشن)."},
        {type:"teach",trg:"das Fett",src:"الدهن، الشحم",pos:"noun",gender:"n",note:"نفس الجذر مثل الإنجليزية 'fat'. 'Fettarm' (قليل الدسم)، 'fettfrei' (خالي الدسم).",example:"A: Gib etwas Fett in die Pfanne.\nB: Butter oder Öl?\nA: Öl ist gesünder.\nB: Aber Butter schmeckt besser!",exampleSrc:"A: ضع بعض الدهن في المقلاة.\nB: زبدة أم زيت؟\nA: الزيت أصح.\nB: لكن الزبدة ألذ!",funFact:"نفس الجذر مثل الإنجليزية 'fat'. 'Ins Fettnäpfchen treten' (الدوس في وعاء الدهن) تعني ارتكاب خطأ اجتماعي."},
        {type:"teach",trg:"der Pilz",src:"الفطر",pos:"noun",gender:"m",note:"من اللاتينية 'pileus' (قبعة). الألمان يجمعون الفطر من الغابات كل خريف.",example:"A: Ich habe frische Pilze vom Markt.\nB: Steinpilze oder Champignons?\nA: Steinpilze! Zum Braten.\nB: Perfekt, mit Butter und Öl.",exampleSrc:"A: لدي فطر طازج من السوق.\nB: بورتشيني أم شامبينيون؟\nA: بورتشيني! للقلي.\nB: ممتاز، مع زبدة وزيت.",funFact:"من اللاتينية 'pileus' (قبعة). الألمان يجمعون الفطر من الغابات كل خريف. 'Pilzsammeln' (جمع الفطر) تقليد محبوب لكنه خطير بدون خبرة."},
        {type:"teach",trg:"die Pflaume",src:"البرقوق",pos:"noun",gender:"f",note:"من اللاتينية 'prunum'. 'Pflaumenkuchen' (كعكة البرقوق) حلوى كلاسيكية في أواخر الصيف.",example:"A: Die Pflaumen sind reif!\nB: Perfekt für Pflaumenkuchen.\nA: Hast du das Rezept von deiner Oma?\nB: Ja, mit Zimt und Streuseln.",exampleSrc:"A: البرقوق ناضج!\nB: مثالي لكعكة البرقوق.\nA: هل لديك وصفة جدتك؟\nB: نعم، بالقرفة والفتات.",funFact:"من اللاتينية 'prunum' عبر التحول الجرماني. 'Pflaumenkuchen' (كعكة البرقوق) حلوى كلاسيكية في أواخر الصيف. بالعامية، 'Du Pflaume!' تعني 'يا غبي!' لكن بلطف."},
        {type:"teach",trg:"die Aprikose",src:"المشمش",pos:"noun",gender:"f",note:"من العربية 'البرقوق' عبر اللاتينية. في النمسا: 'Marille'.",example:"A: Magst du Aprikosen?\nB: Ja, sehr! Besonders als Marmelade.\nA: In Österreich sagt man Marille.\nB: Gleiche Frucht, anderes Wort.",exampleSrc:"A: هل تحب المشمش؟\nB: نعم، كثيراً! خاصة كمربى.\nA: في النمسا يقولون Marille.\nB: نفس الفاكهة، كلمة مختلفة.",funFact:"من العربية 'البرقوق' عبر اللاتينية. في النمسا يقولون 'Marille' بدلاً من Aprikose. نفس الفاكهة، كلمة مختلفة حسب جانب الحدود الذي تقف فيه."},
        {type:"teach",trg:"die Frucht",src:"الفاكهة",pos:"noun",gender:"f",note:"من اللاتينية 'fructus'. الكلمة الرسمية. الألمانية العامية تستخدم 'Obst' للفاكهة الطازجة.",example:"A: Diese Frucht kenne ich nicht.\nB: Das ist eine Kaki. Probier mal!\nA: Mmm, süß und weich.\nB: Früchtetee damit schmeckt auch gut.",exampleSrc:"A: لا أعرف هذه الفاكهة.\nB: هذه كاكي. جرّبها!\nA: ممم، حلوة وناعمة.\nB: شاي الفواكه معها لذيذ أيضاً.",funFact:"من اللاتينية 'fructus'. 'Früchtetee' (شاي الفواكه) هو ما يشربه الألمان عندما لا يريدون كافيين. Die Frucht هي الكلمة الرسمية. الألمانية العامية تستخدم 'Obst' للفاكهة الطازجة."},
        {type:"teach",trg:"das Gebäck",src:"المعجنات، المخبوزات",pos:"noun",gender:"n",note:"من 'backen' (يخبز). بادئة Ge- تجعلها جماعية: كل المخبوزات.",example:"A: Das Gebäck hier ist fantastisch.\nB: Ja, alles frisch vom Bäcker.\nA: Ich nehme ein Croissant und ein Brötchen.\nB: Gute Wahl!",exampleSrc:"A: المعجنات هنا رائعة.\nB: نعم، كل شيء طازج من الخباز.\nA: سآخذ كرواسان وخبزة.\nB: اختيار جيد!",funFact:"من 'backen' (يخبز). بادئة Ge- تجعلها جماعية: كل المخبوزات معاً. بسكويت ومعجنات وخبز. Das Gebäck محايد الجنس، مثل معظم الأسماء الجماعية بـ Ge-."},
        {type:"teach",trg:"drin",src:"فيه، بالداخل (عامي)",pos:"adv",gender:null,note:"اختصار عامي لـ 'darin' (فيه/هناك).\nشائع جداً في الألمانية المنطوقة.",example:"A: Was ist da drin?\nB: Kartoffelsalat und Würstchen.\nA: Ist Pfeffer auch drin?\nB: Ja, und Zwiebeln!",exampleSrc:"A: ماذا بالداخل؟\nB: سلطة بطاطس ونقانق.\nA: هل فيه فلفل أيضاً؟\nB: نعم، وبصل!",funFact:"Drin هي النسخة العامية من darin، كما أن drauf هي العامية لـ darauf وdrüber لـ darüber. في الكلام اليومي، الألمان يستخدمون دائماً تقريباً الصيغ المختصرة."},
        {type:"teach",trg:"das Picknick",src:"النزهة",pos:"noun",gender:"n",note:"مستعارة من الفرنسية 'pique-nique'. حديقة البيرة هي نزهة جماعية دائمة.",example:"A: Wollen wir ein Picknick im Park machen?\nB: Gute Idee! Ich bringe den Salat.\nA: Und ich bringe Brot und Käse.\nB: Perfekt, um drei Uhr am See?",exampleSrc:"A: هل نتنزه في الحديقة؟\nB: فكرة جيدة! سأحضر السلطة.\nA: وأنا سأحضر الخبز والجبن.\nB: ممتاز، الساعة الثالثة عند البحيرة؟",funFact:"مستعارة من الفرنسية 'pique-nique'. الألمان يحبون النزهة في الحديقة: بطانية وخبز وجبن ونبيذ. حديقة البيرة هي أساساً نزهة جماعية دائمة."},
        {type:"teach",trg:"roh",src:"نيء، غير مطبوخ",pos:"adj",gender:null,note:"'Rohes Fleisch' (لحم نيء)، 'Rohkost' (خضروات نيئة/طعام صحي). مرتبط بالإنجليزية 'raw'.",example:"A: Ist das Fleisch noch roh?\nB: Ja, es muss noch zehn Minuten auf den Grill.\nA: Rohes Fleisch ist gefährlich.\nB: Nicht in Deutschland: Mett ist roh und beliebt!",exampleSrc:"A: هل اللحم لا يزال نيئاً؟\nB: نعم، يحتاج عشر دقائق أخرى على الشواية.\nA: اللحم النيء خطير.\nB: ليس في ألمانيا: Mett نيء وشعبي!",funFact:"'Rohes Fleisch' (لحم نيء)، 'Rohkost' (خضروات نيئة/طعام صحي). مرتبط بالإنجليزية 'raw' عبر الجرمانية الأولى. الألمان يأكلون بعض الأشياء نيئة تفاجئ الأجانب: 'Mett' (لحم خنزير مفروم نيء) شيء حقيقي."},
        {type:"teach",trg:"gar",src:"مطبوخ، ناضج",pos:"adj",gender:null,note:"'Das Fleisch ist gar' (اللحم ناضج). أيضاً ظرف: 'gar nicht' (ليس على الإطلاق).",example:"A: Ist die Bratwurst schon gar?\nB: Noch nicht, noch zwei Minuten.\nA: Ich mag sie gar nicht roh.\nB: Keine Sorge, sie wird perfekt!",exampleSrc:"A: هل النقانق ناضجة بعد؟\nB: ليس بعد، دقيقتان إضافيتان.\nA: لا أحبها نيئة على الإطلاق.\nB: لا تقلق، ستكون مثالية!",funFact:"مطبوخ، ناضج (كصفة). 'Das Fleisch ist gar' (اللحم ناضج). أيضاً ظرف بمعنى 'على الإطلاق' أو 'حتى': 'gar nicht' (ليس على الإطلاق). معنيان مختلفان تماماً في كلمة واحدة."},
        {type:"story",speaker:"verumius",mood:"satisfied",art:"de-ber-biergarten-table",trg:"Die Teller kommen. Bratwurst, Kartoffelsalat, frisches Brot. Verumius schaut sich um: alle essen, niemand redet. Nur das Klingen der Gabeln und leises Zufriedenheitsbrummen.",src:"الأطباق تصل. نقانق، سلطة بطاطس، خبز طازج. فيروميوس ينظر حوله: الجميع يأكل، لا أحد يتحدث. فقط قرع الشوك وهمهمات رضا هادئة."},
        {type:"mc",q:"Du musst Zwiebeln braten. Welches Küchengerät brauchst du?",opts:["Dose","Kanne","Pfanne","Schüssel"],ans:"Pfanne",hint:"هذا الشيء يأتي من اللاتينية 'patina' ويُستخدم للقلي على الموقد."},
        {type:"fb",s:"Für den Kuchen brauchen wir {1}, Eier und Zucker.",a:["Mehl"],opts:["Mehl","Fett","Pfeffer","Pilz"],hint:"المسحوق الأبيض الذي يشكل أساس كل الخبز.",sSrc:"للكعكة نحتاج طحيناً وبيضاً وسكراً."},
        {type:"match",pairs:[
            {trg:"roh",src:"raw/uncooked"},
            {trg:"gar",src:"cooked/done"},
            {trg:"Zutat",src:"ingredient"},
            {trg:"Frucht",src:"fruit"}
          ]},
        {type:"teach",trg:"die Marille",src:"المشمش (نمساوي)",pos:"noun",gender:"f",note:"كلمة نمساوية لـ Aprikose. من الإيطالية amarella.\nMarillenknödel = كنيدل المشمش، كلاسيكية نمساوية.",example:"A: Was ist eine Marille?\nB: Das ist die österreichische Aprikose.\nA: Sind Marillen süß?\nB: Ja, sehr süß und fruchtig.",exampleSrc:"A: ما هي Marille؟\nB: هذا هو المشمش النمساوي.\nA: هل Marillen حلوة؟\nB: نعم، حلوة جداً وفاكهية.",funFact:"Marille تأتي من الإيطالية amarella (المرّة الصغيرة). Marillenknödel واحدة من أحب الحلويات النمساوية. منطقة Wachau مشهورة ببساتين المشمش."},
        {type:"mc",q:"In Österreich heißt 'Aprikose' anders. Wie sagt man dort?",opts:["Frucht","Pflaume","Marille","Zwiebel"],ans:"Marille",hint:"هذه هي الكلمة النمساوية لنفس الفاكهة. تأتي من الإيطالية 'amarella'."},
        {type:"fb",s:"Zum Frühstück esse ich gerne frisches {1} vom Bäcker.",a:["Gebäck"],opts:["Gebäck","Picknick","Mehl","Fett"],hint:"الاسم الجماعي لكل المخبوزات، مع بادئة Ge-.",sSrc:"على الإفطار أحب أكل معجنات طازجة من الخباز."}
      ]},
    {id:"deu_r18l3",title:"Die Spargel-Panik",icon:"🥦",xp:15,board:true,steps:[
        {type:"intro",title:"Die Spargel-Panik",desc:"[AR] Heinrich calls in a panic: Spargelzeit ends June 24! Learn the difference between 'als' and 'wenn,' plus food shopping and nutrition vocabulary.",goals:[
            "[AR] Understand the German obsession with Spargelzeit",
            "[AR] Learn als (one-time past) vs wenn (repeated/conditional)",
            "[AR] Pick up food shopping and nutrition vocabulary"
          ]},
        {type:"story",speaker:"narrator",mood:"amused",art:"de-ber-biergarten-table",trg:"Hildis Handy summt. Sie stellt es auf Lautsprecher. Heinrichs Stimme füllt den ganzen Tisch. Er klingt aufgeregt.",src:"[AR] Hildi's phone buzzes. She puts it on speaker. Heinrich's voice fills the whole table. He sounds agitated."},
        {type:"story",speaker:"heinrich",mood:"urgent",trg:"Es ist der zwanzigste Juni! Spargelzeit endet am vierundzwanzigsten! Habt ihr schon Spargel bestellt? Ich bestehe darauf!",src:"[AR] It is the twentieth of June! Asparagus season ends on the twenty-fourth! Have you ordered asparagus yet? I insist!"},
        {type:"story",speaker:"verumius",mood:"confused",trg:"Warum ist Spargel so dringend? Es ist doch nur Gemüse...",src:"[AR] Why is asparagus so urgent? It is just a vegetable..."},
        {type:"story",speaker:"hildi",mood:"explaining",trg:"Als ich ein Kind war, haben wir jedes Jahr auf den ersten Spargel gewartet. Wenn die Saison endet, gibt es keinen mehr. Bis nächstes Jahr.",src:"[AR] When I was a child, we waited every year for the first asparagus. When the season ends, there is no more. Until next year."},
        {type:"story",speaker:"lukas",mood:"laughing",trg:"Heinrich hat recht. Wenn man den letzten Spargel verpasst, ist das eine nationale Tragödie.",src:"[AR] Heinrich is right. If you miss the last asparagus, that is a national tragedy."},
        {type:"story",speaker:"narrator",mood:"warm",art:"de-ber-biergarten-table",trg:"Hildi bestellt sechs Portionen Spargel. Mit Butter und Kartoffeln. Heinrich hört es durch den Lautsprecher und seufzt zufrieden. Dann legt er auf, ohne sich zu verabschieden.",src:"[AR] Hildi orders six portions of asparagus. With butter and potatoes. Heinrich hears it through the speaker and sighs contentedly. Then he hangs up without saying goodbye."},
        {type:"teach",trg:"die Saison",src:"[AR] the season (food/sports)",pos:"noun",gender:"f",note:"[AR] From French 'saison.' Spargelzeit is Germany's most famous food Saison.",example:"A: Wann ist Erdbeer-Saison?\nB: Von Mai bis Juli.\nA: Und Spargel-Saison?\nB: Mitte April bis zum vierundzwanzigsten Juni.",exampleSrc:"[AR] A: When is strawberry season?\nB: From May to July.\nA: And asparagus season?\nB: Mid-April to the twenty-fourth of June.",funFact:"[AR] From French 'saison.' Spargelzeit is Germany's most famous food Saison: mid-April to June 24. Germans eat 1.7 kg of Spargel per person per year."},
        {type:"teach",trg:"die Ernte",src:"[AR] the harvest",pos:"noun",gender:"f",note:"[AR] From 'ernten' (to harvest). 'Erntezeit' (harvest time) is peak season for farmers.",example:"A: Die Ernte war dieses Jahr gut.\nB: Ja, der Sommer war perfekt.\nA: Besonders die Spargelernte.\nB: Die beste seit Jahren!",exampleSrc:"[AR] A: The harvest was good this year.\nB: Yes, the summer was perfect.\nA: Especially the asparagus harvest.\nB: The best in years!",funFact:"[AR] Harvest. From 'ernten' (to harvest). 'Erntezeit' (harvest time) is when German farmers are busiest. The word carries weight in a country where seasonal eating is still important."},
        {type:"teach",trg:"die Quittung",src:"[AR] the receipt",pos:"noun",gender:"f",note:"[AR] From Latin 'quietare' (to settle). Germans keep Quittungen for everything.",example:"A: Kann ich die Quittung haben?\nB: Natürlich, hier bitte.\nA: Ich brauche sie für die Steuererklärung.\nB: Typisch deutsch!",exampleSrc:"[AR] A: Can I have the receipt?\nB: Of course, here you go.\nA: I need it for the tax return.\nB: Typically German!",funFact:"[AR] From Latin 'quietare' (to settle). 'Kann ich die Quittung haben?' is essential shopping vocabulary. Germans keep Quittungen for everything, especially for tax returns."},
        {type:"teach",trg:"der Rabatt",src:"[AR] the discount",pos:"noun",gender:"m",note:"[AR] From Italian 'rabatto.' A discount or reduction.",example:"A: Gibt es einen Rabatt auf den Spargel?\nB: Ja, zehn Prozent, weil die Saison fast vorbei ist.\nA: Dann nehme ich zwei Kilo!\nB: Kluge Entscheidung.",exampleSrc:"[AR] A: Is there a discount on the asparagus?\nB: Yes, ten percent, because the season is almost over.\nA: Then I will take two kilos!\nB: Smart decision.",funFact:"[AR] From Italian 'rabatto' (discount). 'Sonderangebot' (special offer) and 'Rabatt' are the words that make German shoppers happy."},
        {type:"teach",trg:"das Sonderangebot",src:"[AR] the special offer",pos:"noun",gender:"n",note:"[AR] 'Sonder' (special) + 'Angebot' (offer). Neuter because Angebot is neuter.",example:"A: Schau mal, Spargel im Sonderangebot!\nB: Nur drei Euro das Kilo!\nA: Heinrich wäre begeistert.\nB: Ruf ihn an!",exampleSrc:"[AR] A: Look, asparagus on special offer!\nB: Only three euros per kilo!\nA: Heinrich would be thrilled.\nB: Call him!",funFact:"[AR] 'Sonder' (special) + 'Angebot' (offer). German supermarkets advertise Sonderangebote in weekly flyers. Das Sonderangebot is neuter because Angebot is neuter. Compound gender rule."},
        {type:"teach",trg:"die Schlange",src:"[AR] the snake, the queue",pos:"noun",gender:"f",note:"[AR] 'Schlange stehen' (to stand in line) makes the queue a snake.",example:"A: Oh nein, die Schlange ist so lang!\nB: Ja, alle wollen den letzten Spargel.\nA: Wir müssen Schlange stehen.\nB: Das gehört zum deutschen Alltag.",exampleSrc:"[AR] A: Oh no, the queue is so long!\nB: Yes, everyone wants the last asparagus.\nA: We have to stand in line.\nB: That is part of German daily life.",funFact:"[AR] A snake AND a queue. 'Schlange stehen' (to stand in line) makes the queue a snake. Germans queue precisely but not always patiently."},
        {type:"teach",trg:"der Backofen",src:"[AR] the oven",pos:"noun",gender:"m",note:"[AR] 'Back' (bake) + 'Ofen' (oven). Every German kitchen has one.",example:"A: Heize den Backofen auf 180 Grad vor.\nB: Ober- und Unterhitze?\nA: Ja, für den Spargelauflauf.\nB: In zwanzig Minuten ist er heiß.",exampleSrc:"[AR] A: Preheat the oven to 180 degrees.\nB: Top and bottom heat?\nA: Yes, for the asparagus casserole.\nB: It will be hot in twenty minutes.",funFact:"[AR] 'Back' (bake) + 'Ofen' (oven). 'Den Backofen auf 180 Grad vorheizen' (Preheat the oven to 180 degrees) begins every German recipe. Celsius, naturally."},
        {type:"teach",trg:"das Nahrungsmittel",src:"[AR] the foodstuff",pos:"noun",gender:"n",note:"[AR] 'Nahrung' (nourishment) + 'Mittel' (means). The formal, official word for food.",example:"A: Nahrungsmittel müssen korrekt beschriftet sein.\nB: Das steht im Gesetz.\nA: Jede Zutat muss auf der Verpackung stehen.\nB: Deutschland nimmt das ernst.",exampleSrc:"[AR] A: Foodstuffs must be labeled correctly.\nB: That is the law.\nA: Every ingredient must be on the packaging.\nB: Germany takes that seriously.",funFact:"[AR] 'Nahrung' (nourishment) + 'Mittel' (means/agent). The formal, official word for food. You see it on packaging and in regulations. More technical than 'Essen' (food/eating)."},
        {type:"teach",trg:"die Ernährung",src:"[AR] the nutrition, the diet",pos:"noun",gender:"f",note:"[AR] From 'ernähren' (to nourish). Covers your entire relationship with food.",example:"A: Achtest du auf deine Ernährung?\nB: Ja, ich esse viel Obst und Gemüse.\nA: Gesunde Ernährung ist wichtig.\nB: Besonders im Sommer mit frischem Spargel!",exampleSrc:"[AR] A: Do you watch your diet?\nB: Yes, I eat lots of fruit and vegetables.\nA: Healthy nutrition is important.\nB: Especially in summer with fresh asparagus!",funFact:"[AR] From 'ernähren' (to nourish). 'Gesunde Ernährung' (healthy nutrition) is a topic Germans take seriously. Die Ernährung covers your entire relationship with food."},
        {type:"teach",trg:"die Diät",src:"[AR] the diet",pos:"noun",gender:"f",note:"[AR] From Greek 'diaita' (way of life). Can also mean a special medical diet.",example:"A: Machst du eine Diät?\nB: Nein, ich esse einfach weniger Zucker.\nA: Das ist auch eine Art Diät.\nB: Stimmt, aber es fühlt sich nicht so an.",exampleSrc:"[AR] A: Are you on a diet?\nB: No, I just eat less sugar.\nA: That is also a kind of diet.\nB: True, but it does not feel like it.",funFact:"[AR] From Greek 'diaita' (way of life). In German, Diät can also mean a special medical diet, not just weight loss. Politicians' salaries are also called 'Diäten.'"},
        {type:"teach",trg:"das Vitamin",src:"[AR] the vitamin",pos:"noun",gender:"n",note:"[AR] Coined in 1912 from Latin 'vita' (life) + 'amine.' 'Vitamin C' is pronounced 'Vitamin Tsay.'",example:"A: Spargel hat viele Vitamine.\nB: Besonders Vitamin C und K.\nA: Deshalb ist er so gesund.\nB: Und lecker!",exampleSrc:"[AR] A: Asparagus has many vitamins.\nB: Especially vitamin C and K.\nA: That is why it is so healthy.\nB: And delicious!",funFact:"[AR] Coined in 1912 from Latin 'vita' (life) + 'amine.' Germans are vitamin-conscious. 'Vitamin C' is pronounced 'Vitamin Tsay.' The health-food market in Germany is enormous."},
        {type:"teach",trg:"reif",src:"[AR] ripe, mature",pos:"adj",gender:null,note:"[AR] 'Der Apfel ist reif.' Also figurative: 'reif für etwas sein' (to be ready for something).",example:"A: Sind die Erdbeeren schon reif?\nB: Ja, sie sind perfekt rot.\nA: Dann pflücken wir sie heute.\nB: Die reifen sind die süßesten.",exampleSrc:"[AR] A: Are the strawberries ripe yet?\nB: Yes, they are perfectly red.\nA: Then we will pick them today.\nB: The ripe ones are the sweetest.",funFact:"[AR] Ripe, mature. Also used figuratively: 'reif für etwas sein' (to be ready for something). 'Ich bin reif für den Urlaub' (I am ready for vacation)."},
        {type:"teach",trg:"haltbar",src:"[AR] durable, having a shelf life",pos:"adj",gender:null,note:"[AR] 'Halt' (hold) + '-bar' (able). 'Mindestens haltbar bis...' (Best before...).",example:"A: Wie lange ist die Milch haltbar?\nB: Bis nächsten Mittwoch.\nA: Und die Konserven?\nB: Die sind Jahre haltbar.",exampleSrc:"[AR] A: How long does the milk keep?\nB: Until next Wednesday.\nA: And the canned goods?\nB: They keep for years.",funFact:"[AR] 'Halt' (hold) + '-bar' (able). 'Mindestens haltbar bis...' (Best before...) appears on every German food package. The -bar suffix works like English '-able.'"},
        {type:"teach",trg:"vegetarisch",src:"[AR] vegetarian",pos:"adj",gender:null,note:"[AR] From Latin 'vegetare' (to enliven). Germany has high rates of vegetarianism.",example:"A: Gibt es etwas Vegetarisches?\nB: Ja, Kartoffelsalat und Spargelsuppe.\nA: Perfekt, ich esse kein Fleisch.\nB: In Berlin ist das ganz normal.",exampleSrc:"[AR] A: Is there anything vegetarian?\nB: Yes, potato salad and asparagus soup.\nA: Perfect, I do not eat meat.\nB: In Berlin that is completely normal.",funFact:"[AR] From Latin 'vegetare' (to enliven). Germany has one of the highest rates of vegetarianism in Europe. Berlin alone has over 60 fully vegetarian restaurants."},
        {type:"teach",trg:"zubereiten",src:"[AR] to prepare (food)",pos:"verb",gender:null,note:"[AR] 'Zu' (to) + 'bereiten' (to prepare). More specific than 'vorbereiten.' Separable.",example:"A: Wie bereitet man Spargel zu?\nB: Schälen, kochen, mit Butter servieren.\nA: Wie lange kocht er?\nB: Zehn bis fünfzehn Minuten.",exampleSrc:"[AR] A: How do you prepare asparagus?\nB: Peel, boil, serve with butter.\nA: How long does it cook?\nB: Ten to fifteen minutes.",funFact:"[AR] 'Zu' (to) + 'bereiten' (to prepare). More specific than 'vorbereiten' (general preparation). Separable: 'Ich bereite das Essen zu.'"},
        {type:"teach",trg:"mischen",src:"[AR] to mix",pos:"verb",gender:null,note:"[AR] Regular verb. 'Einen Salat mischen' (to toss a salad). Related to English 'mix.'",example:"A: Kannst du den Salat mischen?\nB: Klar, mit welchem Dressing?\nA: Essig und Öl.\nB: Ich mische alles zusammen.",exampleSrc:"[AR] A: Can you toss the salad?\nB: Sure, with which dressing?\nA: Vinegar and oil.\nB: I will mix everything together.",funFact:"[AR] To mix. Regular verb. 'Einen Salat mischen' (to toss a salad), 'Karten mischen' (to shuffle cards). Related to English 'mix' through Latin 'miscere.'"},
        {type:"teach",trg:"spülen",src:"[AR] to rinse, to wash (dishes)",pos:"verb",gender:null,note:"[AR] 'Geschirr spülen' (to wash dishes). Also 'die Toilette spülen' (to flush).",example:"A: Wer spült heute das Geschirr?\nB: Du! Ich habe gestern gespült.\nA: Wir brauchen eine Spülmaschine.\nB: Stimmt, Handspülen dauert ewig.",exampleSrc:"[AR] A: Who washes the dishes today?\nB: You! I washed them yesterday.\nA: We need a dishwasher.\nB: True, hand-washing takes forever.",funFact:"[AR] To rinse or wash (dishes). 'Geschirr spülen' (to wash dishes). Also 'die Toilette spülen' (to flush the toilet). The Spülmaschine is the dishwasher."},
        {type:"tip",title:"als vs wenn: Zwei Wörter für 'when'",text:"[AR] German has two words where English has one.\n\nALS = one specific moment in the past.\n'Als ich ein Kind war...' (When I was a child...)\n'Als Heinrich anrief...' (When Heinrich called...)\n\nWENN = every time, repeatedly, or hypothetically.\n'Wenn ich Spargel esse...' (When/whenever I eat asparagus...)\n'Wenn die Saison endet...' (When the season ends...)\n\nMemory trick:\nALS = ONCE in the past.\nWENN = WHENEVER or IF.\n\nHildi says 'Als ich ein Kind war' (one specific past). Lukas says 'Wenn man den letzten Spargel verpasst' (every year, repeated).",deepDive:"[AR] The distinction is strict in German. You cannot use 'wenn' for a single past event, and you cannot use 'als' for repeated or present events. In reported speech or written German, the rule holds firm. Some learners think 'als' means 'as' and 'wenn' means 'when/if,' but the real key is: was it a one-time past event (als) or is it repeated/habitual/conditional (wenn)?"},
        {type:"verb_table",title:"als vs wenn (when)",note:"[AR] Als = one specific past event. Wenn = repeated, habitual, or hypothetical.",groups:[
            {label:"als (einmalig in der Vergangenheit)",rows:[
                {pronoun:"Als ich ankam,",form:"war alles bereit.",src:"When I arrived, everything was ready."},
                {pronoun:"Als wir Kinder waren,",form:"spielten wir im Garten.",src:"When we were children, we played in the garden."},
                {pronoun:"Als Heinrich anrief,",form:"saßen wir im Biergarten.",src:"When Heinrich called, we were sitting in the beer garden."}
              ]},
            {label:"wenn (wiederholt / hypothetisch)",rows:[
                {pronoun:"Wenn ich Hunger habe,",form:"esse ich Brot.",src:"When(ever) I am hungry, I eat bread."},
                {pronoun:"Wenn die Saison endet,",form:"gibt es keinen Spargel.",src:"When the season ends, there is no asparagus."},
                {pronoun:"Wenn ich könnte,",form:"würde ich jeden Tag grillen.",src:"If I could, I would grill every day."}
              ]}
          ]},
        {type:"mc",q:"Ergänze: '_____ ich gestern im Biergarten war, habe ich Spargel bestellt.'",opts:["Ob","Als","Wenn","Weil"],ans:"Als",hint:"[AR] Yesterday is a single, specific moment in the past. Which word means 'when' for one-time events?"},
        {type:"fb",s:"{1} die Spargelzeit endet, sind die Deutschen immer traurig.",a:["Wenn"],opts:["Wenn","Als","Ob","Weil"],hint:"[AR] The asparagus season ends EVERY year. This is a repeated event.",sSrc:"[AR] When the asparagus season ends, Germans are always sad."}
      ]},
    {id:"deu_r18l4",title:"Worauf freust du dich?",icon:"💡",xp:15,board:true,steps:[
        {type:"intro",title:"Worauf freust du dich?",desc:"[AR] Some German verbs always come with a specific preposition. Learn the combos, then replace them with clever da- and wo- compounds.",goals:[
            "[AR] Master verbs with fixed prepositions (sich freuen auf/über, warten auf, denken an)",
            "[AR] Learn da-compounds (darauf, darüber) to replace prepositional phrases",
            "[AR] Form questions with wo-compounds (worauf, worüber)"
          ]},
        {type:"story",speaker:"mia",mood:"curious",art:"de-ber-biergarten-table",trg:"Worauf freust du dich gerade am meisten, Verumius? Auf den Sommer? Auf das Essen? Oder wartest du auf etwas anderes?",src:"[AR] What are you most looking forward to right now, Verumius? To summer? To the food? Or are you waiting for something else?"},
        {type:"story",speaker:"verumius",mood:"thoughtful",trg:"Ich freue mich über diesen Abend. Und ich denke an zu Hause. Manchmal interessiere ich mich für alles gleichzeitig.",src:"[AR] I am happy about this evening. And I think of home. Sometimes I am interested in everything at the same time."},
        {type:"teach",trg:"der Konsum",src:"[AR] the consumption",pos:"noun",gender:"m",note:"[AR] From Latin 'consumere.' Covers everything from food to media consumption.",example:"A: Der Konsum von Spargel steigt jedes Jahr.\nB: Die Deutschen lieben Spargel.\nA: Der Konsum von Bio-Produkten wächst auch.\nB: Ja, immer mehr Leute kaufen bio.",exampleSrc:"[AR] A: The consumption of asparagus increases every year.\nB: Germans love asparagus.\nA: The consumption of organic products is also growing.\nB: Yes, more and more people buy organic.",funFact:"[AR] From Latin 'consumere.' 'Konsumgesellschaft' (consumer society) is a word Germans use critically. Der Konsum is masculine."},
        {type:"teach",trg:"die Flüssigkeit",src:"[AR] the liquid, the fluid",pos:"noun",gender:"f",note:"[AR] 'Flüssig' (liquid) + '-keit' (noun suffix). The -keit suffix always creates feminine nouns.",example:"A: Trinkst du genug Flüssigkeit?\nB: Ich versuche es. Zwei Liter am Tag.\nA: Bei der Hitze brauchst du mehr.\nB: Stimmt, ich hole mir noch Wasser.",exampleSrc:"[AR] A: Do you drink enough fluids?\nB: I try. Two liters a day.\nA: In this heat you need more.\nB: True, I will get more water.",funFact:"[AR] 'Flüssig' (liquid) + '-keit' (noun suffix). 'Viel Flüssigkeit trinken' (drink plenty of fluids) is standard German health advice. The -keit suffix always creates feminine nouns."},
        {type:"teach",trg:"der Alkohol",src:"[AR] the alcohol",pos:"noun",gender:"m",note:"[AR] From Arabic 'al-kuhl' (the kohl/essence). Germany has relaxed alcohol laws.",example:"A: Trinkst du Alkohol?\nB: Manchmal. Ein Bier im Biergarten.\nA: In Deutschland darf man ab sechzehn Bier trinken.\nB: Ja, aber Schnaps erst ab achtzehn.",exampleSrc:"[AR] A: Do you drink alcohol?\nB: Sometimes. A beer in the beer garden.\nA: In Germany you can drink beer from age sixteen.\nB: Yes, but spirits only from eighteen.",funFact:"[AR] From Arabic 'al-kuhl' (the kohl/essence). Germany has some of the most relaxed alcohol laws in Europe. Beer from age 16, spirits from 18."},
        {type:"teach",trg:"der Kakao",src:"[AR] the cocoa, the hot chocolate",pos:"noun",gender:"m",note:"[AR] From Nahuatl 'cacahuatl' via Spanish. 'Jemanden durch den Kakao ziehen' = to make fun of someone.",example:"A: Möchtest du Kakao oder Kaffee?\nB: Kakao, bitte. Mit Sahne.\nA: Du trinkst immer Kakao!\nB: Ja, das ist mein Lieblingsgetränk.",exampleSrc:"[AR] A: Would you like cocoa or coffee?\nB: Cocoa, please. With cream.\nA: You always drink cocoa!\nB: Yes, that is my favorite drink.",funFact:"[AR] From Nahuatl 'cacahuatl' via Spanish. 'Jemanden durch den Kakao ziehen' (to pull someone through the cocoa) means to make fun of someone."},
        {type:"teach",trg:"die Serviceangestellte",src:"[AR] the service employee (female)",pos:"noun",gender:"f",note:"[AR] 'Service' + 'Angestellte' (employee). Gender-neutral alternative to Kellner/Kellnerin.",example:"A: Entschuldigung, können Sie uns helfen?\nB: Natürlich! Ich bin Ihre Serviceangestellte heute Abend.\nA: Wir hätten gerne die Karte.\nB: Sofort!",exampleSrc:"[AR] A: Excuse me, can you help us?\nB: Of course! I am your service attendant this evening.\nA: We would like the menu.\nB: Right away!",funFact:"[AR] 'Service' + 'Angestellte' (employee). The gender-neutral alternative to Kellner/Kellnerin. Modern German hospitality vocabulary."},
        {type:"teach",trg:"die Vermietung",src:"[AR] the rental, the letting",pos:"noun",gender:"f",note:"[AR] From 'vermieten' (to rent out). Feminine because of -ung.",example:"A: Die Vermietung von Ferienwohnungen boomt.\nB: Besonders in Berlin.\nA: Siehst du das Schild? 'Vermietung ab Juni.'\nB: Vielleicht für den Sommer.",exampleSrc:"[AR] A: The rental of vacation apartments is booming.\nB: Especially in Berlin.\nA: Do you see the sign? 'Rental from June.'\nB: Maybe for the summer.",funFact:"[AR] From 'vermieten' (to rent out). 'Zimmervermietung' (room rental). Die Vermietung is feminine because of -ung. You see it on signs everywhere."},
        {type:"teach",trg:"die Vermittlung",src:"[AR] the mediation, the placement",pos:"noun",gender:"f",note:"[AR] From 'vermitteln' (to mediate/arrange). The -ung ending makes it feminine.",example:"A: Die Vermittlung hat mir eine Wohnung gefunden.\nB: Wie schnell?\nA: In nur zwei Wochen.\nB: Das ist in Berlin ein Wunder!",exampleSrc:"[AR] A: The agency found me an apartment.\nB: How quickly?\nA: In just two weeks.\nB: That is a miracle in Berlin!",funFact:"[AR] From 'vermitteln' (to mediate/arrange). 'Arbeitsvermittlung' (job placement), 'Zimmervermittlung' (accommodation service). The -ung ending makes it feminine."},
        {type:"teach",trg:"die Eröffnung",src:"[AR] the opening, the inauguration",pos:"noun",gender:"f",note:"[AR] From 'eröffnen' (to open formally). A formal event with speeches and ribbon-cutting.",example:"A: Kommst du zur Eröffnung des neuen Biergartens?\nB: Ja, natürlich! Wann ist es?\nA: Nächsten Samstag um zwölf.\nB: Ich bin dabei!",exampleSrc:"[AR] A: Are you coming to the opening of the new beer garden?\nB: Yes, of course! When is it?\nA: Next Saturday at noon.\nB: I will be there!",funFact:"[AR] From 'eröffnen' (to open formally). 'Die Eröffnung des Biergartens' (the opening of the beer garden). Grand openings in Germany involve speeches and ribbon-cutting."},
        {type:"teach",trg:"bio",src:"[AR] organic",pos:"adj",gender:null,note:"[AR] Short for 'biologisch.' 'Bio-Bratwurst,' 'Bio-Bier.' Germany is Europe's largest organic market.",example:"A: Ist die Bratwurst bio?\nB: Ja, vom Bio-Bauernhof.\nA: Dann nehme ich zwei.\nB: Bio ist teurer, aber es lohnt sich.",exampleSrc:"[AR] A: Is the bratwurst organic?\nB: Yes, from an organic farm.\nA: Then I will take two.\nB: Organic is more expensive, but it is worth it.",funFact:"[AR] Short for 'biologisch.' Germany is the largest organic food market in Europe. The 'Bio' label is legally protected and strictly regulated."},
        {type:"teach",trg:"biologisch",src:"[AR] biological, organic",pos:"adj",gender:null,note:"[AR] From Greek 'bios' (life) + 'logos' (study). In food context it means organic.",example:"A: Ist das biologisch angebaut?\nB: Ja, ohne Pestizide.\nA: Biologische Landwirtschaft ist wichtig.\nB: Für die Umwelt und für uns.",exampleSrc:"[AR] A: Is that organically grown?\nB: Yes, without pesticides.\nA: Organic farming is important.\nB: For the environment and for us.",funFact:"[AR] From Greek 'bios' (life) + 'logos' (study). 'Biologische Landwirtschaft' (organic farming). Longer form of 'bio,' used in formal or written contexts."},
        {type:"teach",trg:"mager",src:"[AR] lean, thin, low-fat",pos:"adj",gender:null,note:"[AR] 'Magermilch' (skim milk), 'mageres Fleisch' (lean meat).",example:"A: Hast du Magermilch?\nB: Nein, nur Vollmilch.\nA: Ich achte auf meine Ernährung.\nB: Dann kaufe ich nächstes Mal Magermilch.",exampleSrc:"[AR] A: Do you have skim milk?\nB: No, only whole milk.\nA: I watch my diet.\nB: Then I will buy skim milk next time.",funFact:"[AR] Lean, thin, low-fat. 'Magermilch' (skim milk), 'mageres Fleisch' (lean meat). Not a compliment when applied to food portions."},
        {type:"teach",trg:"spitz",src:"[AR] sharp, pointed",pos:"adj",gender:null,note:"[AR] 'Ein spitzer Stift' (a sharp pencil). Also 'spitze!' as slang for 'great!'",example:"A: Vorsicht, das Messer ist spitz!\nB: Danke, ich passe auf.\nA: Und wie war das Essen?\nB: Spitze!",exampleSrc:"[AR] A: Careful, the knife is sharp!\nB: Thanks, I will be careful.\nA: And how was the food?\nB: Great!",funFact:"[AR] Sharp, pointed. 'Ein spitzer Stift' (a sharp pencil). Also 'spitze!' as slang for 'great!' Related to English 'spit' (the pointed landform)."},
        {type:"teach",trg:"eröffnen",src:"[AR] to open (formally), to inaugurate",pos:"verb",gender:null,note:"[AR] 'Er-' (to begin/achieve) + 'öffnen' (to open). More formal than simply 'öffnen.'",example:"A: Wann eröffnet der neue Biergarten?\nB: Nächste Woche.\nA: Wer eröffnet ihn offiziell?\nB: Der Bürgermeister!",exampleSrc:"[AR] A: When does the new beer garden open?\nB: Next week.\nA: Who officially opens it?\nB: The mayor!",funFact:"[AR] 'Er-' (to begin/achieve) + 'öffnen' (to open). You 'eröffnen' a business, a meeting, or a Biergarten season. More formal than simply 'öffnen' (to open a door)."},
        {type:"teach",trg:"konsumieren",src:"[AR] to consume",pos:"verb",gender:null,note:"[AR] From Latin 'consumere.' More formal than 'essen' or 'trinken.'",example:"A: Deutsche konsumieren viel Bier.\nB: Aber weniger als früher.\nA: Der Konsum sinkt seit Jahren.\nB: Dafür steigt der Weinkonsum.",exampleSrc:"[AR] A: Germans consume a lot of beer.\nB: But less than before.\nA: Consumption has been dropping for years.\nB: But wine consumption is increasing.",funFact:"[AR] From Latin 'consumere.' More formal than 'essen' or 'trinken.' 'Alkohol konsumieren' sounds more official. Used in health contexts and regulations."},
        {type:"teach",trg:"lösen",src:"[AR] to solve, to dissolve, to buy (a ticket)",pos:"verb",gender:null,note:"[AR] Three meanings in one verb. 'Ein Problem lösen,' 'eine Fahrkarte lösen.'",example:"A: Ich muss noch eine Fahrkarte lösen.\nB: Am Automaten oder online?\nA: Online ist einfacher.\nB: Problem gelöst!",exampleSrc:"[AR] A: I still need to buy a ticket.\nB: At the machine or online?\nA: Online is easier.\nB: Problem solved!",funFact:"[AR] To solve, to dissolve, to buy (a ticket). 'Ein Problem lösen,' 'Salz löst sich in Wasser,' 'eine Fahrkarte lösen.' Three meanings, one verb."},
        {type:"teach",trg:"heben",src:"[AR] to lift, to raise",pos:"verb",gender:null,note:"[AR] Strong verb: heben, hob, gehoben. 'Ein Glas heben' (to raise a glass). Related to English 'heave.'",example:"A: Heben wir die Gläser!\nB: Prost! Auf den Sommer!\nA: Dieses Bierglas ist schwer.\nB: Ein Liter! Das ist Training.",exampleSrc:"[AR] A: Let us raise our glasses!\nB: Cheers! To summer!\nA: This beer glass is heavy.\nB: One liter! That is exercise.",funFact:"[AR] Strong verb: heben, hob, gehoben. 'Ein Glas heben' (to raise a glass) is what you do at 'Prost!' Related to English 'heave.'"},
        {type:"tip",title:"Verben mit festen Präpositionen",text:"[AR] Some German verbs always pair with a specific preposition. The preposition changes the meaning.\n\nsich freuen AUF = look forward to (future)\nsich freuen ÜBER = be happy about (present/past)\nwarten AUF = wait for\ndenken AN = think of\nbestehen AUF = insist on\nsich interessieren FÜR = be interested in\n\nYou cannot swap the prepositions. Each combo is one fixed unit. Memorize them as pairs.\n\nExample from the story:\nHeinrich besteht AUF Spargel. (Heinrich insists ON asparagus.)\nVerumius freut sich AUF den Abend. (Verumius looks forward TO the evening.)",deepDive:"[AR] The case after the preposition matters too. 'Auf' with fixed-preposition verbs usually takes accusative: 'Ich warte auf DEN Kellner.' 'An' takes accusative with 'denken': 'Ich denke an DEN Abend.' These differ from the spatial use of the same prepositions, where the two-way prepositions take dative for location and accusative for direction."},
        {type:"verb_table",title:"Verben mit festen Präpositionen",note:"[AR] Each verb-preposition pair is a fixed unit. The preposition determines the case.",groups:[
            {label:"auf (Akkusativ)",rows:[
                {pronoun:"sich freuen auf",form:"Ich freue mich auf den Sommer.",src:"I look forward to summer."},
                {pronoun:"warten auf",form:"Wir warten auf den Kellner.",src:"We wait for the waiter."},
                {pronoun:"bestehen auf",form:"Heinrich besteht auf Spargel.",src:"Heinrich insists on asparagus."}
              ]},
            {label:"über (Akkusativ)",rows:[
                {pronoun:"sich freuen über",form:"Sie freut sich über das Geschenk.",src:"She is happy about the gift."},
                {pronoun:"sprechen über",form:"Wir sprechen über das Essen.",src:"We talk about the food."}
              ]},
            {label:"an (Akkusativ)",rows:[
                {pronoun:"denken an",form:"Ich denke an den Abend.",src:"I think of the evening."},
                {pronoun:"sich erinnern an",form:"Er erinnert sich an den Biergarten.",src:"He remembers the beer garden."}
              ]},
            {label:"für (Akkusativ)",rows:[
                {pronoun:"sich interessieren für",form:"Sie interessiert sich für Bio-Essen.",src:"She is interested in organic food."}
              ]}
          ]},
        {type:"tip",title:"da- und wo-Komposita",text:"[AR] When you want to say 'about it' or 'for it,' German combines da- with a preposition:\n- darauf (on it), darüber (about it), daran (of it), dafür (for it)\n\nFor questions, combine wo- with a preposition:\n- worauf (on what), worüber (about what), woran (of what), wofür (for what)\n\nWhen the preposition starts with a vowel, an -r- is inserted for smoother pronunciation:\n- da- plus auf becomes darauf\n- wo- plus über becomes worüber\n\nExample:\n'Worauf wartest du?' -- 'Darauf, dass der Kellner kommt.'\n(What are you waiting for? -- For the waiter to come.)",deepDive:"[AR] Da-compounds replace prepositional phrases that refer to things (not people). For people, use the preposition plus a pronoun: 'Ich denke an ihn' (I think of him), NOT 'Ich denke daran' when referring to a person. Wo-compounds work the same way: 'An wen denkst du?' (Who are you thinking of?) for people, 'Woran denkst du?' (What are you thinking of?) for things."},
        {type:"mc",q:"Verumius _____ sich _____ den Spargel. (freut sich auf etwas)",opts:["freut...über","wartet...auf","freut...auf","denkt...an"],ans:"freut...auf",hint:"[AR] Looking forward to something in the FUTURE uses 'sich freuen' plus the preposition for future anticipation."},
        {type:"mc",q:"Heinrich besteht auf Spargel. Er besteht _____ .",opts:["darüber","dafür","daran","darauf"],ans:"darauf",hint:"[AR] The verb is 'bestehen AUF.' Replace 'auf Spargel' with da + auf."},
        {type:"fb",s:"{1} freust du dich? -- Auf den Sommer!",a:["Worauf"],opts:["Worauf","Worüber","Woran","Wofür"],hint:"[AR] The answer uses 'auf.' The question word combines 'wo' with 'auf.'",sSrc:"[AR] What are you looking forward to? -- To summer!"},
        {type:"mc",q:"'_____ ich das erste Mal Spargel aß, war ich überrascht.' Welches Wort passt?",opts:["Weil","Damit","Als","Wenn"],ans:"Als",hint:"[AR] The FIRST time is a single, one-time past event. Which word is for that?"},
        {type:"drag_fill",s:"Mia {1} sich {2} Bio-Essen. Sie denkt oft {3}.",blanks:{"1":"interessiert","2":"für","3":"daran"},pool:["interessiert","für","daran","freut","auf","darauf"],hint:"[AR] First: the verb for being interested plus its fixed preposition. Second: 'denken an' replaced with a da-compound.",sSrc:"[AR] Mia is interested in organic food. She often thinks about it."},
        {type:"match",pairs:[
            {trg:"darauf",src:"on it / for it"},
            {trg:"darüber",src:"about it"},
            {trg:"daran",src:"of it / to it"},
            {trg:"dafür",src:"for it (purpose)"}
          ]}
      ]},
    {id:"deu_r18l5",title:"Lukas spielt",icon:"🎸",xp:15,board:true,steps:[
        {type:"intro",title:"Lukas spielt",desc:"[AR] The golden hour fades to blue. Fairy lights glow. Lukas picks up his guitar. His band broke up last month. Tonight, he plays alone.",goals:[
            "[AR] Practice als vs wenn in emotional contexts",
            "[AR] Use verbs with fixed prepositions to describe feelings",
            "[AR] Learn nature and agriculture vocabulary"
          ]},
        {type:"story",speaker:"narrator",mood:"reflective",art:"de-ber-biergarten-dusk",trg:"Die goldene Stunde geht in Blau über. Lichterketten erwachen in den Kastanienästen. Lukas steht auf der kleinen erhöhten Fläche, Gitarre in der Hand. Niemand hat ihn gebeten zu spielen. Er hat einfach angefangen.",src:"[AR] The golden hour fades to blue. Fairy lights come alive in the chestnut branches. Lukas stands on the small raised area, guitar in hand. No one asked him to play. He just started."},
        {type:"story",speaker:"mia",mood:"quiet",trg:"Sie beugt sich zu Verumius: 'Seine Band hat sich letzten Monat getrennt. Er spricht nicht darüber. Aber er denkt ständig daran.'",src:"[AR] She leans toward Verumius: 'His band broke up last month. He does not talk about it. But he thinks about it constantly.'"},
        {type:"story",speaker:"narrator",mood:"emotional",art:"de-ber-biergarten-guitar",trg:"Lukas spielt. Augen geschlossen. Die Musik ist schön und traurig. Ein Lied über Sommerabende, die nicht ewig dauern. Hildi stellt ihren Bierkrug ab. Sogar sie ist still.",src:"[AR] Lukas plays. Eyes closed. The music is beautiful and sad. A song about summer evenings that will not last. Hildi puts down her beer stein. Even she is quiet."},
        {type:"story",speaker:"verumius",mood:"thinking",trg:"Als ich ihn zum ersten Mal traf, war er immer lustig. Jetzt verstehe ich: Wenn er Musik macht, zeigt er, was er wirklich fühlt.",src:"[AR] When I first met him, he was always funny. Now I understand: when he makes music, he shows what he really feels."},
        {type:"story",speaker:"hildi",mood:"gentle",art:"de-ber-biergarten-dusk",trg:"Lukas setzt sich. Hildi schiebt ihm ein Bier hin, ohne ein Wort. Am Nebentisch klatscht jemand. Dann noch einer. Lukas lächelt, zum ersten Mal heute Abend richtig.",src:"[AR] Lukas sits down. Hildi slides a beer toward him without a word. At the next table someone claps. Then another. Lukas smiles, properly for the first time this evening."},
        {type:"teach",trg:"die Wiese",src:"[AR] the meadow",pos:"noun",gender:"f",note:"[AR] 'Liegewiese' (sunbathing lawn) is where Germans spread blankets in parks.",example:"A: Lass uns auf die Wiese setzen.\nB: Ja, das Gras ist weich.\nA: Die Wiese ist voller Blumen.\nB: Ein perfekter Sommerabend.",exampleSrc:"[AR] A: Let us sit on the meadow.\nB: Yes, the grass is soft.\nA: The meadow is full of flowers.\nB: A perfect summer evening.",funFact:"[AR] A meadow. 'Liegewiese' (sunbathing lawn) is where Germans spread their blankets in parks. 'Auf der grünen Wiese' is also business jargon for building from scratch."},
        {type:"teach",trg:"das Gras",src:"[AR] the grass",pos:"noun",gender:"n",note:"[AR] Same word and same root as English. 'Das Gras wachsen hören' = to be overly perceptive.",example:"A: Das Gras im Park ist so grün.\nB: Ja, es hat viel geregnet.\nA: Perfekt zum Picknicken.\nB: Aber nicht zu nass?",exampleSrc:"[AR] A: The grass in the park is so green.\nB: Yes, it rained a lot.\nA: Perfect for a picnic.\nB: But not too wet?",funFact:"[AR] Same word and same root as English. 'Das Gras wachsen hören' (to hear the grass grow) means to be overly sensitive or perceptive."},
        {type:"teach",trg:"das Feld",src:"[AR] the field",pos:"noun",gender:"n",note:"[AR] Cognate with English 'field.' Germany's agricultural Felder feed much of Europe.",example:"A: Schau dir die Felder an!\nB: Getreide, so weit man sehen kann.\nA: Die Ernte wird gut dieses Jahr.\nB: Ja, der Regen war perfekt.",exampleSrc:"[AR] A: Look at the fields!\nB: Grain, as far as you can see.\nA: The harvest will be good this year.\nB: Yes, the rain was perfect.",funFact:"[AR] Cognate with English 'field.' 'Feldforschung' (field research), 'Spielfeld' (playing field). Germany's agricultural Felder feed much of Europe."},
        {type:"teach",trg:"das Tuch",src:"[AR] the cloth, the scarf",pos:"noun",gender:"n",note:"[AR] 'Halstuch' (neck scarf), 'Handtuch' (towel), 'Tischtuch' (tablecloth).",example:"A: Hast du ein Tuch dabei?\nB: Ja, mein Halstuch. Warum?\nA: Es wird kühler am Abend.\nB: Stimmt, nimm es.",exampleSrc:"[AR] A: Do you have a scarf with you?\nB: Yes, my neck scarf. Why?\nA: It is getting cooler in the evening.\nB: True, take it.",funFact:"[AR] A cloth or scarf. German compounds with Tuch name every type of fabric you drape: 'Halstuch' (neck scarf), 'Handtuch' (hand-cloth = towel), 'Tischtuch' (tablecloth)."},
        {type:"teach",trg:"der Sack",src:"[AR] the sack, the bag",pos:"noun",gender:"m",note:"[AR] Same word as English. In Austria: 'Sackerl' replaces 'Tüte' for a small bag.",example:"A: Bring bitte einen Sack Kartoffeln mit.\nB: Vom Markt oder vom Supermarkt?\nA: Vom Markt, die sind frischer.\nB: Gut, ich nehme einen großen Sack.",exampleSrc:"[AR] A: Please bring a sack of potatoes.\nB: From the market or the supermarket?\nA: From the market, they are fresher.\nB: Good, I will take a big sack.",funFact:"[AR] Same word as English. In Austria and southern Germany, 'Sackerl' replaces 'Tüte' for a small bag. 'Die Katze aus dem Sack lassen' (let the cat out of the bag) works in German too."},
        {type:"teach",trg:"die Büchse",src:"[AR] the can, the tin, the box",pos:"noun",gender:"f",note:"[AR] 'Konservenbüchse' (tin can). In some regions, Büchse and Dose are interchangeable.",example:"A: Öffne mal die Büchse mit den Bohnen.\nB: Wo ist der Dosenöffner?\nA: In der Schublade.\nB: Gefunden!",exampleSrc:"[AR] A: Open the can of beans.\nB: Where is the can opener?\nA: In the drawer.\nB: Found it!",funFact:"[AR] A can, tin, or box. 'Konservenbüchse' (tin can). In some regions, Büchse and Dose are interchangeable. Also historically a rifle or musket, from the cylindrical shape."},
        {type:"teach",trg:"der Kloß",src:"[AR] the dumpling",pos:"noun",gender:"m",note:"[AR] Plural: Klöße. In southern Germany: Knödel. Classic side dish.",example:"A: Magst du Klöße?\nB: Ja! Kartoffelklöße sind mein Lieblingsbeilage.\nA: In Bayern sagt man Knödel.\nB: Gleich lecker, egal wie man es nennt.",exampleSrc:"[AR] A: Do you like dumplings?\nB: Yes! Potato dumplings are my favorite side.\nA: In Bavaria they say Knödel.\nB: Equally delicious, no matter what you call them.",funFact:"[AR] A dumpling. Plural: Klöße. In southern Germany: Knödel. 'Einen Kloß im Hals haben' (to have a dumpling in your throat) means to be choked up with emotion."},
        {type:"teach",trg:"der Koch",src:"[AR] the cook, the chef",pos:"noun",gender:"m",note:"[AR] From Latin 'coquus.' 'Viele Köche verderben den Brei' (Too many cooks spoil the porridge).",example:"A: Der Koch hier ist fantastisch.\nB: Ja, alles schmeckt perfekt.\nA: Er kocht seit zwanzig Jahren.\nB: Erfahrung macht den Koch.",exampleSrc:"[AR] A: The chef here is fantastic.\nB: Yes, everything tastes perfect.\nA: He has been cooking for twenty years.\nB: Experience makes the chef.",funFact:"[AR] From Latin 'coquus.' 'Viele Köche verderben den Brei' (Too many cooks spoil the porridge). Same proverb, same meaning, same ancient wisdom."},
        {type:"teach",trg:"die Köchin",src:"[AR] the cook, the chef (female)",pos:"noun",gender:"f",note:"[AR] Koch + -in. More women lead professional kitchens in Germany now.",example:"A: Die Köchin hat ein neues Rezept.\nB: Was gibt es heute?\nA: Spargelsuppe mit Brötchen.\nB: Klingt wunderbar!",exampleSrc:"[AR] A: The chef has a new recipe.\nB: What is there today?\nA: Asparagus soup with bread rolls.\nB: Sounds wonderful!",funFact:"[AR] Female cook. Koch + -in. More and more women lead professional kitchens in Germany, though the industry still has a long way to go."},
        {type:"teach",trg:"die Landwirtschaft",src:"[AR] the agriculture",pos:"noun",gender:"f",note:"[AR] 'Land' (country/land) + 'Wirtschaft' (economy). Feminine because of -schaft.",example:"A: Die Landwirtschaft in Brandenburg ist wichtig.\nB: Ja, viele Bauernhöfe dort.\nA: Spargel kommt oft aus Brandenburg.\nB: Das beste Spargelgebiet Deutschlands!",exampleSrc:"[AR] A: Agriculture in Brandenburg is important.\nB: Yes, many farms there.\nA: Asparagus often comes from Brandenburg.\nB: The best asparagus region in Germany!",funFact:"[AR] 'Land' (country/land) + 'Wirtschaft' (economy/management). Germany's agricultural sector feeds 80 million people efficiently."},
        {type:"teach",trg:"aufwachen",src:"[AR] to wake up",pos:"verb",gender:null,note:"[AR] 'Auf' (up) + 'wachen' (to be awake). Separable: 'Ich wache um sechs auf.'",example:"A: Wann bist du aufgewacht?\nB: Um sechs Uhr. Die Vögel haben mich geweckt.\nA: Im Sommer wache ich auch früh auf.\nB: Das Licht kommt so früh!",exampleSrc:"[AR] A: When did you wake up?\nB: At six o'clock. The birds woke me.\nA: In summer I also wake up early.\nB: The light comes so early!",funFact:"[AR] 'Auf' (up) + 'wachen' (to be awake). Not to be confused with 'aufwecken' (to wake someone else up). Aufwachen is what you do. Aufwecken is what your alarm does to you."},
        {type:"teach",trg:"blühen",src:"[AR] to bloom, to blossom",pos:"verb",gender:null,note:"[AR] From the same root as 'Blume' (flower) and 'Blüte' (blossom).",example:"A: Die Rosen blühen wunderschön.\nB: Ja, der Garten sieht toll aus.\nA: Im Frühling blüht alles.\nB: Meine Lieblingszeit!",exampleSrc:"[AR] A: The roses are blooming beautifully.\nB: Yes, the garden looks great.\nA: In spring everything blooms.\nB: My favorite time!",funFact:"[AR] To bloom, to blossom. Also figurative: 'Das Geschäft blüht' (Business is blooming). From the same root as 'Blume' (flower) and 'Blüte' (blossom)."},
        {type:"teach",trg:"nähern",src:"[AR] to approach, to come closer",pos:"verb",gender:null,note:"[AR] Often reflexive: 'sich nähern.' From 'nah' (near).",example:"A: Wir nähern uns dem Biergarten.\nB: Ich rieche schon die Bratwurst!\nA: Noch fünf Minuten.\nB: Ich kann es kaum erwarten.",exampleSrc:"[AR] A: We are approaching the beer garden.\nB: I can already smell the bratwurst!\nA: Five more minutes.\nB: I can hardly wait.",funFact:"[AR] To approach, to come closer. Often reflexive: 'sich nähern.' 'Wir nähern uns dem Ziel' (We are approaching the goal). From 'nah' (near)."},
        {type:"teach",trg:"pflanzen",src:"[AR] to plant",pos:"verb",gender:null,note:"[AR] From Latin 'planta.' 'Einen Baum pflanzen.' Also a noun: die Pflanze (the plant).",example:"A: Hast du die Tomaten gepflanzt?\nB: Ja, gestern Nachmittag.\nA: Wann können wir ernten?\nB: In ungefähr zwei Monaten.",exampleSrc:"[AR] A: Did you plant the tomatoes?\nB: Yes, yesterday afternoon.\nA: When can we harvest?\nB: In about two months.",funFact:"[AR] From Latin 'planta.' Germans take gardening seriously: Kleingärten (allotment gardens) are a national institution."},
        {type:"teach",trg:"wachsen",src:"[AR] to grow",pos:"verb",gender:null,note:"[AR] Strong verb: wachsen, wuchs, gewachsen. Not to be confused with 'wachsen' (to wax).",example:"A: Der Spargel wächst unter der Erde.\nB: Deshalb ist er weiß?\nA: Genau! Ohne Licht bleibt er weiß.\nB: Faszinierend!",exampleSrc:"[AR] A: Asparagus grows under the ground.\nB: That is why it is white?\nA: Exactly! Without light it stays white.\nB: Fascinating!",funFact:"[AR] Strong verb: wachsen, wuchs, gewachsen. 'Kinder wachsen schnell.' Not to be confused with 'wachsen' (to wax), which is a different verb with different origins."},
        {type:"teach",trg:"gießen",src:"[AR] to pour, to water (plants)",pos:"verb",gender:null,note:"[AR] Strong verb: goss, gegossen. 'Blumen gießen,' 'Es gießt' (It is pouring rain).",example:"A: Kannst du die Blumen gießen?\nB: Klar, die sehen trocken aus.\nA: Jeden Abend gießen im Sommer.\nB: Sonst gehen sie ein.",exampleSrc:"[AR] A: Can you water the flowers?\nB: Sure, they look dry.\nA: Water them every evening in summer.\nB: Otherwise they will die.",funFact:"[AR] To pour or to water (plants). 'Blumen gießen' (to water flowers). Strong verb: goss, gegossen. 'Es gießt' means 'It is pouring rain.'"},
        {type:"mc",q:"Lukas sagt: '_____ ich das letzte Konzert mit meiner Band spielte, wusste ich nicht, dass es das letzte war.'",opts:["Wenn","Als","Obwohl","Weil"],ans:"Als",hint:"[AR] The last concert was a single, specific moment in the past."},
        {type:"fb",s:"Mia sagt: Lukas spricht nicht {1} seine Band.",a:["über"],opts:["über","auf","an","für"],hint:"[AR] The verb 'sprechen' pairs with which preposition to mean 'talk about'?",sSrc:"[AR] Mia says: Lukas does not talk about his band."},
        {type:"mc",q:"Lukas denkt oft an seine Band. Er denkt oft _____ .",opts:["dafür","darauf","darüber","daran"],ans:"daran",hint:"[AR] 'Denken AN' requires da + an. What is da + an?"},
        {type:"drag_fill",s:"{1} Lukas seine Band hatte, spielten sie jeden Freitag. {2} er jetzt allein spielt, klingt es anders.",blanks:{"1":"Als","2":"Wenn"},pool:["Als","Wenn","Weil","Dass","Ob"],hint:"[AR] First blank: having the band was a specific period in the past. Second blank: playing alone is a repeated present situation.",sSrc:"[AR] When Lukas had his band, they played every Friday. When he plays alone now, it sounds different."},
        {type:"mc",q:"Wie fragt man 'Woran denkt Lukas?' auf Englisch?",opts:[
            "What is Lukas interested in?",
            "What is Lukas thinking about?",
            "What is Lukas waiting for?",
            "What is Lukas happy about?"
          ],ans:"What is Lukas thinking about?",hint:"[AR] The verb is 'denken AN.' The wo-compound combines wo + an."},
        {type:"fb",s:"Die Blumen auf der {1} blühen im Sommer.",a:["Wiese"],opts:["Wiese","Feld","Gras","Landwirtschaft"],hint:"[AR] The word for a meadow where flowers and grass grow.",sSrc:"[AR] The flowers on the meadow bloom in summer."}
      ]},
    {id:"deu_r18l6",title:"Dialekt auf dem Teller",icon:"🇦🇹",xp:15,board:true,steps:[
        {type:"intro",title:"Dialekt auf dem Teller",desc:"[AR] German is not one language but many regional flavors. Learn farming vocabulary, then discover what Austrians and Swiss call their food.",goals:[
            "[AR] Learn words for farming, residents, and pets",
            "[AR] Discover Austrian and Swiss German food vocabulary",
            "[AR] Understand regional identity through food words"
          ]},
        {type:"story",speaker:"hildi",mood:"animated",art:"de-ber-biergarten-table",trg:"Wisst ihr, als ich ein Kind in Salzburg war, sagten wir nie Kartoffel. Immer Erdapfel. Und Tomaten? Paradeiser! Berlin hat mir das ausgetrieben, aber manchmal rutscht es mir raus.",src:"[AR] You know, when I was a child in Salzburg, we never said Kartoffel. Always Erdapfel. And tomatoes? Paradeiser! Berlin trained it out of me, but sometimes it slips out."},
        {type:"story",speaker:"lukas",mood:"teasing",art:"de-ber-biergarten-table",trg:"Moment. Du bist aus Salzburg? Ich dachte immer, du bist eine echte Berlinerin. Hildi, du bist doch auch eine Zugezogene!",src:"[AR] Wait. You are from Salzburg? I always thought you were a real Berliner. Hildi, you are also someone who moved here!"},
        {type:"teach",trg:"der Bauer",src:"[AR] the farmer",pos:"noun",gender:"m",note:"[AR] From Old High German 'giburo' (neighbor). Also the pawn in chess.",example:"A: Der Bauer verkauft frischen Spargel.\nB: Direkt vom Feld!\nA: Bauernmärkte sind in Berlin beliebt.\nB: Jeden Samstag am Maybachufer.",exampleSrc:"[AR] A: The farmer sells fresh asparagus.\nB: Straight from the field!\nA: Farmers' markets are popular in Berlin.\nB: Every Saturday at Maybachufer.",funFact:"[AR] From Old High German 'giburo' (neighbor, fellow dweller). Also the pawn in chess. 'Bauernregel' (farmer's rule) = weather proverbs based on centuries of agricultural observation."},
        {type:"teach",trg:"der Bauernhof",src:"[AR] the farm",pos:"noun",gender:"m",note:"[AR] 'Bauer' + 'Hof' (yard/farm). Masculine because Hof is masculine.",example:"A: Warst du schon mal auf einem Bauernhof?\nB: Ja, als Kind. Wir haben Urlaub dort gemacht.\nA: Urlaub auf dem Bauernhof ist toll für Kinder.\nB: Und für Erwachsene!",exampleSrc:"[AR] A: Have you ever been to a farm?\nB: Yes, as a child. We vacationed there.\nA: Farm vacations are great for children.\nB: And for adults!",funFact:"[AR] 'Bauer' + 'Hof' (yard/farm). 'Urlaub auf dem Bauernhof' (vacation on a farm) is a popular German family holiday."},
        {type:"teach",trg:"der Bewohner",src:"[AR] the resident, the inhabitant",pos:"noun",gender:"m",note:"[AR] From 'bewohnen' (to inhabit). The Be- prefix + wohnen = who lives somewhere.",example:"A: Wie viele Bewohner hat das Haus?\nB: Zwölf Parteien.\nA: Kennen sich alle?\nB: Die meisten, ja. Wir grillen zusammen.",exampleSrc:"[AR] A: How many residents does the building have?\nB: Twelve parties.\nA: Does everyone know each other?\nB: Most of them, yes. We barbecue together.",funFact:"[AR] From 'bewohnen' (to inhabit). 'Die Bewohner des Hauses' (the residents of the building). The Be- prefix + wohnen makes it about who lives somewhere."},
        {type:"teach",trg:"die Bewohnerin",src:"[AR] the resident (female)",pos:"noun",gender:"f",note:"[AR] Bewohner + -in. On official forms: 'Bewohner/Bewohnerin.'",example:"A: Sind Sie Bewohnerin dieses Hauses?\nB: Ja, seit fünf Jahren.\nA: Dann kennen Sie sicher Frau Schmidt.\nB: Natürlich, sie wohnt über mir.",exampleSrc:"[AR] A: Are you a resident of this building?\nB: Yes, for five years.\nA: Then you surely know Mrs. Schmidt.\nB: Of course, she lives above me.",funFact:"[AR] Female resident. On official forms: 'Bewohner/Bewohnerin' or the modern 'Bewohnende' (gender-neutral)."},
        {type:"teach",trg:"der Mieter",src:"[AR] the tenant",pos:"noun",gender:"m",note:"[AR] From 'mieten' (to rent). Over 50% of Germans rent rather than own.",example:"A: Der Mieter im dritten Stock zieht aus.\nB: Schade, er war nett.\nA: Wer wird der neue Mieter?\nB: Keine Ahnung, aber die Nachfrage ist groß.",exampleSrc:"[AR] A: The tenant on the third floor is moving out.\nB: Too bad, he was nice.\nA: Who will be the new tenant?\nB: No idea, but demand is high.",funFact:"[AR] From 'mieten' (to rent). Germany is a nation of renters: over 50% of Germans rent rather than own their home. Der Mieter has strong legal protections."},
        {type:"teach",trg:"die Mieterin",src:"[AR] the tenant (female)",pos:"noun",gender:"f",note:"[AR] Mieter + -in. German rental law is among the most tenant-friendly in the world.",example:"A: Die Mieterin hat sich beschwert.\nB: Worüber?\nA: Über den Lärm vom Biergarten.\nB: Verständlich, aber es ist Sommer!",exampleSrc:"[AR] A: The tenant complained.\nB: About what?\nA: About the noise from the beer garden.\nB: Understandable, but it is summer!",funFact:"[AR] Female tenant. German rental law (Mietrecht) is among the most tenant-friendly in the world. Evictions are difficult. Rent caps exist."},
        {type:"teach",trg:"das Haustier",src:"[AR] the pet",pos:"noun",gender:"n",note:"[AR] 'Haus' (house) + 'Tier' (animal). Neuter because Tier is neuter.",example:"A: Hast du ein Haustier?\nB: Ja, eine Katze.\nA: Haustiere dürfen in Biergärten meistens mit.\nB: Meine Katze bleibt lieber zu Hause.",exampleSrc:"[AR] A: Do you have a pet?\nB: Yes, a cat.\nA: Pets are usually allowed in beer gardens.\nB: My cat prefers to stay home.",funFact:"[AR] 'Haus' (house) + 'Tier' (animal). Germans love their Haustiere: 34 million pets, more than in most European countries. Dogs can ride public transit."},
        {type:"teach",trg:"die Marille",src:"المشمش (نمساوي)",pos:"noun",gender:"f",note:"[AR] Austrian for 'Aprikose.' From Italian 'amarella' (little bitter one).",example:"A: In Wien sagt man Marille.\nB: Und in Berlin Aprikose.\nA: Marillenknödel sind österreichisch.\nB: Und unglaublich lecker!",exampleSrc:"[AR] A: In Vienna they say Marille.\nB: And in Berlin Aprikose.\nA: Apricot dumplings are Austrian.\nB: And incredibly delicious!",funFact:"[AR] Austrian for 'Aprikose' (apricot). From Italian 'amarella' (little bitter one). 'Marillenknödel' (apricot dumplings) are Austria's most famous dessert."},
        {type:"teach",trg:"der Paradeiser",src:"[AR] the tomato (Austrian)",pos:"noun",gender:"m",note:"[AR] Austrian for 'Tomate.' From 'Paradiesapfel' (paradise apple).",example:"A: Gib mir bitte einen Paradeiser.\nB: Du meinst eine Tomate?\nA: In Österreich sagen wir Paradeiser.\nB: Paradiesapfel, wie poetisch!",exampleSrc:"[AR] A: Please pass me a Paradeiser.\nB: You mean a tomato?\nA: In Austria we say Paradeiser.\nB: Paradise apple, how poetic!",funFact:"[AR] Austrian for 'Tomate.' From Italian 'pomodoro' (golden apple) via 'Paradiesapfel' (paradise apple). Austrians still call the tomato a 'paradise fruit.'"},
        {type:"teach",trg:"der Erdapfel",src:"[AR] the potato (Austrian/Swiss)",pos:"noun",gender:"m",note:"[AR] 'Erd' (earth) + 'Apfel' (apple). French says the same: 'pomme de terre.'",example:"A: Erdapfelsalat zum Schnitzel?\nB: Unbedingt! In Österreich gehört das zusammen.\nA: Kartoffelsalat in Deutschland.\nB: Erdapfelsalat in Wien. Gleiches Gericht.",exampleSrc:"[AR] A: Potato salad with the schnitzel?\nB: Absolutely! In Austria they belong together.\nA: Kartoffelsalat in Germany.\nB: Erdapfelsalat in Vienna. Same dish.",funFact:"[AR] Austrian/Swiss for 'Kartoffel' (potato). 'Erd' (earth) + 'Apfel' (apple). An earth apple. French says the same: 'pomme de terre.' Three names for one vegetable."},
        {type:"teach",trg:"das Henderl",src:"[AR] the chicken (Austrian)",pos:"noun",gender:"n",note:"[AR] Austrian diminutive. The -erl suffix is the Austrian form of -chen.",example:"A: Ein halbes Henderl, bitte!\nB: Mit Kartoffelsalat?\nA: Natürlich!\nB: Kommt sofort.",exampleSrc:"[AR] A: Half a chicken, please!\nB: With potato salad?\nA: Of course!\nB: Coming right up.",funFact:"[AR] Austrian dialect for a small chicken. The -erl suffix is the Austrian diminutive (like -chen in standard German). 'Ein halbes Henderl' is a classic Austrian Gasthaus order."},
        {type:"teach",trg:"das Hendl",src:"[AR] the chicken (Bavarian)",pos:"noun",gender:"n",note:"[AR] Bavarian dialect. Even shorter than Henderl. Neuter because of the diminutive.",example:"A: Auf dem Oktoberfest gibt es Hendl.\nB: Hendl mit Kartoffelsalat!\nA: Das klassische Oktoberfest-Essen.\nB: Dazu eine Maß Bier.",exampleSrc:"[AR] A: At Oktoberfest there is chicken.\nB: Chicken with potato salad!\nA: The classic Oktoberfest meal.\nB: With a liter of beer.",funFact:"[AR] Bavarian dialect for chicken. Even shorter than Henderl. 'Hendl mit Kartoffelsalat' is the quintessential Oktoberfest meal."},
        {type:"teach",trg:"das Obers",src:"[AR] the cream (Austrian)",pos:"noun",gender:"n",note:"[AR] Austrian for 'Sahne.' From 'das Obere' (the top part) because cream rises to the top.",example:"A: Kaffee mit Obers, bitte.\nB: In Deutschland sagt man Sahne.\nA: Aber Obers klingt schöner.\nB: Finde ich auch!",exampleSrc:"[AR] A: Coffee with cream, please.\nB: In Germany they say Sahne.\nA: But Obers sounds nicer.\nB: I think so too!",funFact:"[AR] Austrian for 'Sahne' (cream). From 'das Obere' (the top part) because cream rises to the top of milk. 'Kaffee mit Obers' is how you order coffee with cream in Vienna."},
        {type:"teach",trg:"der Schwammerl",src:"[AR] the mushroom (Bavarian/Austrian)",pos:"noun",gender:"m",note:"[AR] The -erl diminutive. 'Schwammerlsuppe' (mushroom soup) is Bavarian comfort food.",example:"A: Gehen wir Schwammerl suchen!\nB: Im Wald? Ist das nicht gefährlich?\nA: Nicht, wenn man sich auskennt.\nB: Schwammerlsuppe wäre toll.",exampleSrc:"[AR] A: Let us go mushroom hunting!\nB: In the forest? Is that not dangerous?\nA: Not if you know what you are doing.\nB: Mushroom soup would be great.",funFact:"[AR] Bavarian/Austrian for 'Pilz' (mushroom). 'Schwammerlsuppe' (mushroom soup) is comfort food in Bavaria and Austria. Standard German 'Pilz' sounds clinical by comparison."},
        {type:"teach",trg:"der Fleischhauer",src:"[AR] the butcher (Austrian)",pos:"noun",gender:"m",note:"[AR] 'Fleisch' (meat) + 'Hauer' (one who chops). The word paints a picture.",example:"A: Wo ist der nächste Fleischhauer?\nB: In Österreich sagt man Fleischhauer.\nA: In Deutschland Metzger oder Fleischer.\nB: Drei Wörter, ein Beruf.",exampleSrc:"[AR] A: Where is the nearest butcher?\nB: In Austria they say Fleischhauer.\nA: In Germany Metzger or Fleischer.\nB: Three words, one trade.",funFact:"[AR] Austrian for 'Metzger' (butcher). 'Fleisch' (meat) + 'Hauer' (one who chops). Standard German has Metzger (south) and Fleischer (north). Three words, one trade."},
        {type:"teach",trg:"das Backrohr",src:"[AR] the oven (Austrian)",pos:"noun",gender:"n",note:"[AR] 'Back' (bake) + 'Rohr' (pipe/tube). The oven as a baking tube.",example:"A: Schieb den Kuchen ins Backrohr!\nB: Auf welcher Temperatur?\nA: 180 Grad, wie immer.\nB: In Deutschland sagt man Backofen.",exampleSrc:"[AR] A: Put the cake in the oven!\nB: At what temperature?\nA: 180 degrees, as always.\nB: In Germany they say Backofen.",funFact:"[AR] Austrian for 'Backofen' (oven). 'Back' (bake) + 'Rohr' (pipe/tube). The oven as a baking tube. Same appliance, Austrian name."},
        {type:"teach",trg:"das Brötli",src:"[AR] the bread roll (Swiss)",pos:"noun",gender:"n",note:"[AR] Swiss diminutive. The -li suffix is the Swiss form of -chen.",example:"A: Ein Brötli mit Butter, bitte.\nB: In Zürich sagt man Brötli.\nA: In Berlin Brötchen, in München Semmel.\nB: Jede Region hat ihr eigenes Wort!",exampleSrc:"[AR] A: A bread roll with butter, please.\nB: In Zurich they say Brötli.\nA: In Berlin Brötchen, in Munich Semmel.\nB: Every region has its own word!",funFact:"[AR] Swiss German for 'Brötchen' (bread roll). The -li suffix is the Swiss diminutive. Every German-speaking country has its own word for a bread roll."},
        {type:"teach",trg:"die Glace",src:"[AR] the ice cream (Swiss)",pos:"noun",gender:"f",note:"[AR] Swiss German for 'Eis.' From French 'glace' (ice). Shows French influence.",example:"A: Möchtest du eine Kugel Glace?\nB: In der Schweiz sagt man so.\nA: Eine Kugel Glace in Bern, eine Kugel Eis in Berlin.\nB: Hauptsache, es schmeckt!",exampleSrc:"[AR] A: Would you like a scoop of ice cream?\nB: In Switzerland they say it that way.\nA: A scoop of Glace in Bern, a scoop of Eis in Berlin.\nB: The main thing is it tastes good!",funFact:"[AR] Swiss German for 'Eis' (ice cream). From French 'glace' (ice). Switzerland's French influence shows in its food vocabulary."},
        {type:"tip",title:"Drei Länder, drei Küchen",text:"[AR] German is spoken in Germany, Austria, and Switzerland (plus Liechtenstein, Luxembourg, and parts of Belgium and Italy). Each country has unique food vocabulary.\n\nStandard German is understood everywhere, but regional terms carry identity:\n\nTomate (DE) = Paradeiser (AT)\nKartoffel (DE) = Erdapfel (AT/CH)\nSahne (DE) = Obers (AT)\nBrötchen (DE) = Semmel (BY/AT) = Brötli (CH)\nEis (DE) = Glace (CH)\nPilz (DE) = Schwammerl (BY/AT)\n\nThe Biergarten is Bavarian. The Beisl is Austrian. The Beiz is Swiss. Same concept: a place to eat, drink, and belong.",deepDive:"[AR] Knowing regional variants shows respect and cultural awareness. Austrian German (Österreichisches Deutsch) and Swiss Standard German (Schweizer Hochdeutsch) are officially recognized standard varieties, not dialects. They have their own dictionaries and official vocabulary lists."},
        {type:"story",speaker:"verumius",mood:"amused",art:"de-ber-biergarten-table",trg:"Drei Länder, drei Sprachen, ein Spargel. Verumius schreibt heimlich eine Liste auf eine Serviette: Paradeiser, Erdapfel, Obers, Schwammerl. Das Deutsch auf der Speisekarte reicht nicht. Man braucht mindestens drei Speisekarten.",src:"[AR] Three countries, three languages, one asparagus. Verumius secretly writes a list on a napkin: Paradeiser, Erdapfel, Obers, Schwammerl. The German on the menu is not enough. You need at least three menus."},
        {type:"mc",q:"In Österreich heißt 'Sahne' (cream) wie?",opts:["Brötli","Obers","Glace","Paradeiser"],ans:"Obers",hint:"[AR] This word comes from 'das Obere' because cream rises to the top of the milk."},
        {type:"fb",s:"In Wien bestellt man 'Kaffee mit {1}' statt 'Kaffee mit Sahne.'",a:["Obers"],opts:["Obers","Glace","Marille","Erdapfel"],hint:"[AR] The Austrian word for cream, from 'the top part' of milk.",sSrc:"[AR] In Vienna you order 'coffee with Obers' instead of 'coffee with Sahne.'"},
        {type:"match",pairs:[
            {trg:"Marille",src:"Aprikose"},
            {trg:"Paradeiser",src:"Tomate"},
            {trg:"Erdapfel",src:"Kartoffel"},
            {trg:"Schwammerl",src:"Pilz"}
          ]},
        {type:"mc",q:"'Die Bewohner warten _____ den Frühling.' Welche Präposition ergänzt 'warten'?",opts:["auf","für","über","an"],ans:"auf",hint:"[AR] Warten always pairs with this preposition. You wait ON something."},
        {type:"mc",q:"'_____ ich in Wien war, habe ich zum ersten Mal Marillenknödel probiert.'",opts:["Wenn","Als","Damit","Weil"],ans:"Als",hint:"[AR] Being in Vienna was a specific trip in the past. One time."}
      ]},
    {id:"deu_r18l7",title:"Prost und Wiederholung",icon:"🍻",xp:15,board:true,steps:[
        {type:"intro",title:"Prost und Wiederholung",desc:"[AR] Time to prove your skills. Review all Unit 18 grammar, vocabulary, and cultural knowledge in a comprehensive assessment.",goals:[
            "[AR] Test als vs wenn in varied contexts",
            "[AR] Prove mastery of verbs with fixed prepositions",
            "[AR] Use da-/wo- compounds fluently"
          ]},
        {type:"story",speaker:"narrator",mood:"festive",art:"de-ber-biergarten-evening",trg:"Der Abend neigt sich. Lichterketten glühen heller, als der Himmel dunkler wird. Hildi hebt ihren Bierkrug. Die anderen folgen. Sechs Gläser klirren gleichzeitig. Augenkontakt, wie es sich gehört.",src:"[AR] The evening draws on. Fairy lights glow brighter as the sky grows darker. Hildi raises her beer stein. The others follow. Six glasses clink at once. Eye contact, as is proper."},
        {type:"teach",trg:"der Abt",src:"[AR] the abbot",pos:"noun",gender:"m",note:"[AR] From Latin 'abbas.' Many German breweries were founded by monks.",example:"A: Der Abt leitete das Kloster.\nB: Und die Brauerei!\nA: Klosterbier hat eine lange Tradition.\nB: Manche Klöster brauen noch heute.",exampleSrc:"[AR] A: The abbot led the monastery.\nB: And the brewery!\nA: Monastery beer has a long tradition.\nB: Some monasteries still brew today.",funFact:"[AR] From Latin 'abbas.' Many German breweries were founded by monks, and the Abt supervised beer production. 'Klosterbier' (monastery beer) has a centuries-old tradition."},
        {type:"teach",trg:"der Abwart",src:"[AR] the caretaker (Swiss)",pos:"noun",gender:"m",note:"[AR] Swiss German for 'Hausmeister.' 'Ab' (away) + 'Wart' (one who watches).",example:"A: Der Abwart kümmert sich um das Gebäude.\nB: In Deutschland sagt man Hausmeister.\nA: In der Schweiz ist es der Abwart.\nB: Wieder ein regionales Wort!",exampleSrc:"[AR] A: The caretaker takes care of the building.\nB: In Germany they say Hausmeister.\nA: In Switzerland it is the Abwart.\nB: Another regional word!",funFact:"[AR] Swiss German for 'Hausmeister' (caretaker/janitor). 'Ab' (away) + 'Wart' (one who watches). The person who watches over a building."},
        {type:"teach",trg:"die Abwartin",src:"[AR] the caretaker (female, Swiss)",pos:"noun",gender:"f",note:"[AR] Abwart + -in. Swiss German follows the same -in pattern for feminine forms.",example:"A: Die Abwartin hat den Flur geputzt.\nB: Sie macht das jeden Morgen.\nA: In der Schweiz sagt man Abwartin.\nB: Und in Deutschland Hausmeisterin.",exampleSrc:"[AR] A: The caretaker cleaned the hallway.\nB: She does that every morning.\nA: In Switzerland they say Abwartin.\nB: And in Germany Hausmeisterin.",funFact:"[AR] Female caretaker. Swiss German follows the same -in pattern for feminine forms as standard German."},
        {type:"teach",trg:"der Bub",src:"[AR] the boy (Bavarian/Austrian/Swiss)",pos:"noun",gender:"m",note:"[AR] Southern German for 'Junge.' Used across all southern German-speaking regions.",example:"A: Der Bub spielt im Garten.\nB: In Bayern sagt man Bub.\nA: In Norddeutschland sagt man Junge.\nB: Nord-Süd-Unterschied, wie immer.",exampleSrc:"[AR] A: The boy is playing in the garden.\nB: In Bavaria they say Bub.\nA: In northern Germany they say Junge.\nB: North-south difference, as always.",funFact:"[AR] Bavarian/Austrian/Swiss for 'Junge' (boy). 'Ein lieber Bub.' In northern Germany, nobody says Bub. Another north-south divide."},
        {type:"teach",trg:"der Feber",src:"[AR] February (Austrian)",pos:"noun",gender:"m",note:"[AR] Austrian for 'Februar.' Shortened, localized. Instantly marks someone as Austrian.",example:"A: Im Feber ist es kalt in Wien.\nB: Feber? Du meinst Februar?\nA: In Österreich sagen wir Feber.\nB: Wieder was gelernt!",exampleSrc:"[AR] A: In Feber it is cold in Vienna.\nB: Feber? You mean February?\nA: In Austria we say Feber.\nB: Learned something new!",funFact:"[AR] Austrian for 'Februar.' One of those calendar words that instantly tells you someone is Austrian."},
        {type:"teach",trg:"das Poulet",src:"[AR] the chicken (Swiss)",pos:"noun",gender:"n",note:"[AR] From French 'poulet.' Switzerland's French influence again.",example:"A: Poulet mit Pommes, bitte.\nB: In Zürich sagt man Poulet.\nA: In Berlin Hähnchen, in München Hendl.\nB: Drei Länder, drei Hühner!",exampleSrc:"[AR] A: Chicken with fries, please.\nB: In Zurich they say Poulet.\nA: In Berlin Hähnchen, in Munich Hendl.\nB: Three countries, three chickens!",funFact:"[AR] Swiss German for 'Hähnchen' (chicken). From French 'poulet.' 'Poulet mit Pommes' in Zurich = 'Hähnchen mit Pommes' in Berlin = 'Hendl mit Pommes' in Munich."},
        {type:"teach",trg:"ein paar",src:"[AR] a few, some",pos:"pron",gender:null,note:"[AR] Written lowercase. 'Ein Paar' (capitalized) = a pair/couple. Case matters!",example:"A: Ich brauche ein paar Minuten.\nB: Kein Problem, nimm dir Zeit.\nA: Ein paar Freunde kommen später.\nB: Je mehr, desto besser!",exampleSrc:"[AR] A: I need a few minutes.\nB: No problem, take your time.\nA: A few friends are coming later.\nB: The more, the merrier!",funFact:"[AR] Written lowercase (unlike 'ein Paar' = a pair/couple). 'Ein paar Freunde' = a few friends. 'Ein Paar Schuhe' = a pair of shoes. The capital P changes the meaning entirely."},
        {type:"teach",trg:"halt",src:"[AR] just, simply (particle)",pos:"part",gender:null,note:"[AR] 'Das ist halt so.' Extremely common in spoken German, especially southern.",example:"A: Warum regnet es so viel?\nB: Das ist halt Sommer in Berlin.\nA: Ich wollte im Biergarten sitzen.\nB: Dann musst du halt warten.",exampleSrc:"[AR] A: Why does it rain so much?\nB: That is just how summer is in Berlin.\nA: I wanted to sit in the beer garden.\nB: Then you just have to wait.",funFact:"[AR] A particle meaning 'just, simply.' 'Das ist halt so' (That is just how it is). Extremely common in spoken German, especially southern. Signals acceptance or resignation."},
        {type:"teach",trg:"extra",src:"[AR] extra, on purpose, especially",pos:"adv",gender:null,note:"[AR] Same as English. Also means 'on purpose': 'Das hast du extra gemacht!'",example:"A: Ich habe extra für dich Spargel gekauft.\nB: Wie nett von dir!\nA: Der letzte der Saison.\nB: Extra für mich? Danke!",exampleSrc:"[AR] A: I bought asparagus especially for you.\nB: How nice of you!\nA: The last of the season.\nB: Especially for me? Thanks!",funFact:"[AR] Same as English 'extra.' Also means 'on purpose': 'Das hast du extra gemacht!' (You did that on purpose!)."},
        {type:"teach",trg:"gratis",src:"[AR] free (of charge)",pos:"adv",gender:null,note:"[AR] From Latin 'gratis.' Also 'kostenlos' or 'umsonst.'",example:"A: Ist der Eintritt gratis?\nB: Ja, der Biergarten ist frei zugänglich.\nA: Und das Wasser?\nB: Auch gratis, zum Bier dazu.",exampleSrc:"[AR] A: Is admission free?\nB: Yes, the beer garden is freely accessible.\nA: And the water?\nB: Also free, with the beer.",funFact:"[AR] From Latin 'gratis' (for free). 'Der Eintritt ist gratis.' Germans also say 'kostenlos' (costless) or 'umsonst' (for nothing)."},
        {type:"teach",trg:"jedes Mal",src:"[AR] every time",pos:"adv",gender:null,note:"[AR] 'Jedes' (every) + 'Mal' (time). Perfect with 'wenn' for repeated actions.",example:"A: Jedes Mal, wenn ich hier bin, bestelle ich Spargel.\nB: Du bist wie Heinrich!\nA: Jedes Mal schmeckt es anders.\nB: Das macht es spannend.",exampleSrc:"[AR] A: Every time I am here, I order asparagus.\nB: You are like Heinrich!\nA: Every time it tastes different.\nB: That makes it exciting.",funFact:"[AR] 'Jedes' (every) + 'Mal' (time/instance). 'Jedes Mal, wenn ich im Biergarten bin, bestelle ich Spargel.' Perfect with 'wenn' for repeated actions."},
        {type:"teach",trg:"nebenbei",src:"[AR] on the side, incidentally, by the way",pos:"adv",gender:null,note:"[AR] 'Neben' (beside) + 'bei' (by). A useful conversational filler.",example:"A: Nebenbei bemerkt, der Spargel war fantastisch.\nB: Finde ich auch!\nA: Und nebenbei: Lukas hat toll gespielt.\nB: Ja, wirklich beeindruckend.",exampleSrc:"[AR] A: By the way, the asparagus was fantastic.\nB: I think so too!\nA: And incidentally: Lukas played great.\nB: Yes, really impressive.",funFact:"[AR] 'Neben' (beside) + 'bei' (by). 'Nebenbei bemerkt...' (By the way...). Also 'nebenbei arbeiten' (to work on the side). A useful conversational filler."},
        {type:"teach",trg:"au",src:"[AR] ouch, ow",pos:"intj",gender:null,note:"[AR] An exclamation of pain or surprise. Short for 'Aua!' Also a place name element.",example:"A: Au! Das war heiß!\nB: Vorsicht mit dem Grill!\nA: Au, mein Finger!\nB: Zeig mal, ist es schlimm?",exampleSrc:"[AR] A: Ouch! That was hot!\nB: Careful with the grill!\nA: Ow, my finger!\nB: Let me see, is it bad?",funFact:"[AR] An exclamation of pain or surprise. 'Au! Das war heiß!' Short for 'Aua!' Also a place name element: 'Au' means a water meadow."},
        {type:"teach",trg:"der Blitz",src:"[AR] the lightning, the flash",pos:"noun",gender:"m",note:"[AR] Also 'Blitzkrieg' (lightning war), 'Blitzeis' (flash ice). Fast and sudden.",example:"A: Hast du den Blitz gesehen?\nB: Ja! Und dann der Donner!\nA: Ein Gewitter im Biergarten.\nB: Schnell, unter das Dach!",exampleSrc:"[AR] A: Did you see the lightning?\nB: Yes! And then the thunder!\nA: A thunderstorm in the beer garden.\nB: Quick, under the roof!",funFact:"[AR] Same word as English 'blitz.' 'Blitzschnell' (lightning fast), 'Blitzeis' (flash ice on roads). Also the camera flash. Germans say 'Blitz' when a summer storm interrupts a Biergarten evening."},
        {type:"story",speaker:"kd",mood:"dry",art:"de-ber-biergarten-evening",trg:"KD stellt sein Glas ab und sagt leise: 'Jedes Mal, wenn wir hier sitzen, bestellt ihr Spargel. Jedes Mal diskutiert ihr über Dialekte. Und jedes Mal sagt jemand Prost, als wäre es eine Entdeckung.' Mia lacht. 'Das nennt man Tradition, KD.'",src:"[AR] KD puts down his glass and says quietly: 'Every time we sit here, you order asparagus. Every time you argue about dialects. And every time someone says Prost as if it were a discovery.' Mia laughs. 'That is called tradition, KD.'"},
        {type:"mc",q:"'Jedes Mal, _____ wir im Biergarten sind, bestellt Hildi Spargel.' Welches Wort passt?",opts:["wenn","obwohl","als","weil"],ans:"wenn",hint:"[AR] 'Jedes Mal' signals repetition. Which 'when' word is for repeated events?"},
        {type:"mc",q:"Heinrich _____ auf frischem Spargel zum Mittagessen.",opts:["denkt","freut sich","wartet","besteht"],ans:"besteht",hint:"[AR] Which verb means 'to insist' and pairs with 'auf'?"},
        {type:"fb",s:"Mia interessiert sich für Bio-Essen. Sie interessiert sich {1}.",a:["dafür"],opts:["dafür","darauf","darüber","daran"],hint:"[AR] The verb is 'sich interessieren FÜR.' Replace 'für Bio-Essen' with da + für.",sSrc:"[AR] Mia is interested in organic food. She is interested in it."},
        {type:"mc",q:"Du willst fragen 'Worüber freust du dich?' Was bedeutet das auf Englisch?",opts:["What are you happy about?","What are you waiting for?","What are you thinking of?","What are you interested in?"],ans:"What are you happy about?",hint:"[AR] The wo-compound wo + über asks about the topic of a feeling. Which preposition does 'sich freuen' pair with for current feelings?"},
        {type:"drag_fill",s:"{1} ich zum ersten Mal Spargel aß, freute ich mich {2}. Jetzt freue ich mich {3} Mal {4}.",blanks:{"1":"Als","2":"darüber","3":"jedes","4":"darauf"},pool:["Als","Wenn","darüber","darauf","daran","jedes","jede","dafür"],hint:"[AR] First: one-time past event. Second: happy ABOUT it (past, da + über). Third + fourth: every time, looking forward to it (future, da + auf).",sSrc:"[AR] When I ate asparagus for the first time, I was happy about it. Now I look forward to it every time."},
        {type:"mc",q:"'Poulet' ist das Schweizer Wort für...",opts:["Hähnchen","Schweinefleisch","Rindfleisch","Lamm"],ans:"Hähnchen",hint:"[AR] This word comes from French and refers to poultry."},
        {type:"fb",s:"Der Eintritt zum Biergarten ist {1}. Man muss nichts bezahlen.",a:["gratis"],opts:["gratis","extra","halt","nebenbei"],hint:"[AR] A word from Latin meaning 'for free.'",sSrc:"[AR] Admission to the beer garden is free. You do not have to pay anything."},
        {type:"match",pairs:[
            {trg:"Als ich ankam",src:"When I arrived (one time)"},
            {trg:"Wenn ich esse",src:"When(ever) I eat"},
            {trg:"sich freuen auf",src:"to look forward to"},
            {trg:"Worauf wartest du?",src:"What are you waiting for?"}
          ]},
        {type:"mc",q:"'_____ wartet Verumius?' -- 'Auf den Kellner. Er wartet _____.'",opts:["Worauf...darauf","Woran...daran","Wofür...dafür","Worüber...darüber"],ans:"Worauf...darauf",hint:"[AR] 'Warten AUF' is the fixed combo. Question = wo + auf. Answer = da + auf."},
        {type:"drag_fill",s:"{1} wir im Biergarten saßen, rief Heinrich an. Er bestand {2}, dass wir Spargel bestellen.",blanks:{"1":"Als","2":"darauf"},pool:["Als","Wenn","darauf","darüber","daran","Weil"],hint:"[AR] First blank: one specific past moment (als vs. wenn). Second blank: bestehen takes a fixed preposition. Replace 'auf etwas' with the da-compound.",sSrc:"[AR] When we were sitting in the beer garden, Heinrich called. He insisted that we order asparagus."}
      ]},
    {id:"deu_r18l8",title:"Der Nachhauseweg",icon:"🌙",xp:15,board:true,steps:[
        {type:"intro",title:"Der Nachhauseweg",desc:"[AR] Berlin summer night. The group walks home together, splitting off one by one. Final vocabulary, final grammar assessment, and a moment of belonging.",goals:[
            "[AR] Learn remaining vocabulary for food, farming, and daily life",
            "[AR] Master all three grammar constructs in combination",
            "[AR] Reflect on friendship and belonging"
          ]},
        {type:"story",speaker:"narrator",mood:"warm",art:"de-ber-summer-night-street",trg:"Berliner Sommernacht. Die Gruppe strömt aus dem Biergarten. Straßenlaternen leuchten durch Lindenbäume. Die Luft ist warm. Mia schaut auf ihr Handy, ob die letzte U-Bahn noch fährt.",src:"[AR] Berlin summer night. The group spills out of the beer garden. Streetlights glow through linden trees. The air is warm. Mia checks her phone for the last U-Bahn."},
        {type:"story",speaker:"mia",mood:"happy",trg:"Das war ein schöner Abend. Wir sollten das öfter machen. Jedes Mal, wenn wir uns treffen, fühlt es sich wie Zuhause an.",src:"[AR] That was a lovely evening. We should do this more often. Every time we meet, it feels like home."},
        {type:"story",speaker:"hildi",mood:"soft",trg:"Als mein Mann noch lebte, gingen wir jeden Sommer in den Biergarten. Ich hatte mich so darauf gefreut, heute wieder dort zu sein.",src:"[AR] When my husband was still alive, we went to the beer garden every summer. I had looked forward to being there again today."},
        {type:"story",speaker:"lukas",mood:"quiet",trg:"Danke für heute. Ich habe lange nicht gespielt. Ich freue mich darüber, dass ihr zugehört habt.",src:"[AR] Thanks for today. I have not played in a long time. I am happy that you listened."},
        {type:"story",speaker:"verumius",mood:"belonging",art:"de-ber-building-entrance-night",trg:"Verumius geht die letzten Meter allein. Der Hauseingang ist vor ihm. Hildis Licht brennt schon oben. Er denkt: 'Als ich nach Berlin kam, kannte ich niemanden. Jetzt wartet jemand auf mich.'",src:"[AR] Verumius walks the last meters alone. The building entrance is ahead. Hildi's light is already on upstairs. He thinks: 'When I came to Berlin, I knew no one. Now someone is waiting for me.'"},
        {type:"teach",trg:"der Metzger",src:"[AR] the butcher",pos:"noun",gender:"m",note:"[AR] Standard southern German. Northern: 'Fleischer.' Austrian: 'Fleischhauer.' Three words, one trade.",example:"A: Ich gehe zum Metzger.\nB: Bring bitte Bratwurst mit!\nA: Vom Metzger oder vom Supermarkt?\nB: Vom Metzger, die schmeckt besser.",exampleSrc:"[AR] A: I am going to the butcher.\nB: Please bring bratwurst!\nA: From the butcher or the supermarket?\nB: From the butcher, it tastes better.",funFact:"[AR] Standard southern German. Northern Germans say 'Fleischer,' Austrians say 'Fleischhauer.' From Latin 'macellarius' (slaughterer). Every region defends its word."},
        {type:"teach",trg:"ernähren",src:"[AR] to nourish, to feed",pos:"verb",gender:null,note:"[AR] Reflexive: 'sich ernähren' (to eat, to sustain oneself). From 'Nahrung.'",example:"A: Wie ernährst du dich?\nB: Ich ernähre mich meistens vegetarisch.\nA: Das ist gesund.\nB: Und gut für die Umwelt.",exampleSrc:"[AR] A: How do you eat?\nB: I eat mostly vegetarian.\nA: That is healthy.\nB: And good for the environment.",funFact:"[AR] Reflexive: 'sich ernähren' (to eat, to sustain oneself). 'Sich gesund ernähren' (to eat healthily). The er- prefix makes it about achieving nourishment."},
        {type:"teach",trg:"fressen",src:"[AR] to eat (for animals)",pos:"verb",gender:null,note:"[AR] Using 'fressen' for a person is rude. Humans 'essen,' animals 'fressen.'",example:"A: Die Katze frisst ihr Futter.\nB: Sie frisst immer so schnell.\nA: Sag nie 'fressen' über einen Menschen!\nB: Warum nicht?\nA: Das ist sehr unhöflich.",exampleSrc:"[AR] A: The cat eats its food.\nB: She always eats so fast.\nA: Never say 'fressen' about a person!\nB: Why not?\nA: That is very rude.",funFact:"[AR] To eat (for animals). 'Der Hund frisst.' Using 'fressen' for a person is rude: 'Er frisst wie ein Schwein' (He eats like a pig). The distinction matters."},
        {type:"teach",trg:"füttern",src:"[AR] to feed (an animal or baby)",pos:"verb",gender:null,note:"[AR] From 'Futter' (animal food/feed). 'Die Enten füttern' (to feed the ducks).",example:"A: Dürfen wir die Enten füttern?\nB: Ja, aber nur mit Haferflocken.\nA: Kein Brot?\nB: Nein, Brot ist schlecht für Enten.",exampleSrc:"[AR] A: Can we feed the ducks?\nB: Yes, but only with oat flakes.\nA: No bread?\nB: No, bread is bad for ducks.",funFact:"[AR] From 'Futter' (animal food/feed). Also slang: 'Ich muss meinen Computer füttern' (I need to feed data into my computer)."},
        {type:"teach",trg:"grillieren",src:"[AR] to barbecue (Swiss)",pos:"verb",gender:null,note:"[AR] Swiss German for 'grillen.' The -ieren suffix shows French influence.",example:"A: Wollen wir am Wochenende grillieren?\nB: In der Schweiz sagt man grillieren.\nA: In Deutschland grillen.\nB: Gleicher Rauch, anderes Verb!",exampleSrc:"[AR] A: Shall we barbecue this weekend?\nB: In Switzerland they say grillieren.\nA: In Germany grillen.\nB: Same smoke, different verb!",funFact:"[AR] Swiss German for 'grillen.' The -ieren suffix shows French influence. In Switzerland: 'Wir grillieren am See.' In Germany: 'Wir grillen im Park.'"},
        {type:"teach",trg:"nähen",src:"[AR] to sew",pos:"verb",gender:null,note:"[AR] From Old High German 'najen.' Related to English 'needle.'",example:"A: Kannst du nähen?\nB: Ja, ich nähe meine Knöpfe selbst an.\nA: Ich brauche eine Nähmaschine.\nB: Für große Projekte lohnt sich das.",exampleSrc:"[AR] A: Can you sew?\nB: Yes, I sew my own buttons on.\nA: I need a sewing machine.\nB: For big projects it is worth it.",funFact:"[AR] To sew. From Old High German 'najen.' Related to English 'needle' through the same root. 'Mit heißer Nadel genäht' (sewn with a hot needle) means done hastily."},
        {type:"teach",trg:"nützen",src:"[AR] to be useful, to use",pos:"verb",gender:null,note:"[AR] Southern/Austrian variant of 'nutzen.' Both are correct.",example:"A: Das nützt nichts.\nB: Doch, es nützt mehr als du denkst.\nA: In Österreich sagt man nützen.\nB: In Deutschland auch nutzen.",exampleSrc:"[AR] A: That is no use.\nB: Yes it is, it helps more than you think.\nA: In Austria they say nützen.\nB: In Germany also nutzen.",funFact:"[AR] Southern German and Austrian variant of 'nutzen.' Both are correct. The ü vs u distinction is regional, not grammatical."},
        {type:"teach",trg:"nutzen",src:"[AR] to use, to make use of",pos:"verb",gender:null,note:"[AR] Standard German variant. 'Die Gelegenheit nutzen' (to seize the opportunity).",example:"A: Nutze die Gelegenheit!\nB: Welche Gelegenheit?\nA: Der letzte Spargel der Saison!\nB: Du hast recht, ich nutze sie.",exampleSrc:"[AR] A: Seize the opportunity!\nB: Which opportunity?\nA: The last asparagus of the season!\nB: You are right, I will seize it.",funFact:"[AR] 'Die Gelegenheit nutzen' (to seize the opportunity). 'Nutzen' as a noun (der Nutzen) means benefit. Verb and noun share the same form."},
        {type:"teach",trg:"runterwerfen",src:"[AR] to throw down",pos:"verb",gender:null,note:"[AR] 'Runter' (down) + 'werfen' (to throw). Separable. Colloquial contraction of 'herunterwerfen.'",example:"A: Wirf das nicht runter!\nB: Entschuldigung, es ist mir aus der Hand gerutscht.\nA: Der Bierkrug ist fast runtergefallen.\nB: Zum Glück nicht!",exampleSrc:"[AR] A: Do not throw that down!\nB: Sorry, it slipped out of my hand.\nA: The beer stein almost fell down.\nB: Luckily not!",funFact:"[AR] 'Runter' (down) + 'werfen' (to throw). Separable. Colloquial contraction of 'herunterwerfen.' Spoken German loves shortening."},
        {type:"teach",trg:"verpflegen",src:"[AR] to cater, to provide food and care",pos:"verb",gender:null,note:"[AR] From 'Pflege' (care) + ver- prefix. 'Die Gäste verpflegen.'",example:"A: Wer verpflegt die Gäste heute?\nB: Der Koch und seine Köchin.\nA: Die Verpflegung war ausgezeichnet.\nB: Ja, alles frisch und lecker.",exampleSrc:"[AR] A: Who caters for the guests today?\nB: The chef and his cook.\nA: The catering was excellent.\nB: Yes, everything fresh and delicious.",funFact:"[AR] From 'Pflege' (care) + ver- prefix. 'Verpflegung' (catering/provisions) appears on conference schedules. The word covers providing complete food and care."},
        {type:"teach",trg:"bio-",src:"[AR] organic, biological (prefix)",pos:"noun",gender:null,note:"[AR] Prefix meaning organic. 'Bio-Markt,' 'Bio-Bauer,' 'Bio-Milch.' Legally protected in the EU.",example:"A: Kaufst du im Bio-Markt ein?\nB: Ja, meistens Bio-Gemüse.\nA: Bio-Produkte sind teurer.\nB: Aber die Qualität lohnt sich.",exampleSrc:"[AR] A: Do you shop at the organic market?\nB: Yes, mostly organic vegetables.\nA: Organic products are more expensive.\nB: But the quality is worth it.",funFact:"[AR] Prefix meaning organic or biological. In German, bio- attaches to almost any food noun. The prefix alone on a label means certified organic under EU regulation."},
        {type:"teach",trg:"einzel-",src:"[AR] single, individual (prefix)",pos:"noun",gender:null,note:"[AR] 'Einzelzimmer' (single room), 'Einzelkind' (only child), 'Einzelhandel' (retail).",example:"A: Ich brauche ein Einzelzimmer.\nB: Für wie viele Nächte?\nA: Drei. Und bitte kein Einzelkind-Zuschlag.\nB: Kein Problem!",exampleSrc:"[AR] A: I need a single room.\nB: For how many nights?\nA: Three. And please no single supplement.\nB: No problem!",funFact:"[AR] Prefix meaning single or individual. 'Einzelzimmer' (single room), 'Einzelkind' (only child), 'Einzelhandel' (retail). One of German's most productive compound prefixes."},
        {type:"mc",q:"'_____ Verumius nach Berlin kam, kannte er niemanden.' Welches Wort?",opts:["Wenn","Weil","Als","Obwohl"],ans:"Als",hint:"[AR] Arriving in Berlin was a single event in the past."},
        {type:"mc",q:"Lukas freut sich darüber, dass seine Freunde zugehört haben. Was ersetzt 'darüber'?",opts:[
            "für + die Tatsache, dass sie zugehört haben",
            "über + die Tatsache, dass sie zugehört haben",
            "auf + die Tatsache, dass sie zugehört haben",
            "an + die Tatsache, dass sie zugehört haben"
          ],ans:"über + die Tatsache, dass sie zugehört haben",hint:"[AR] Darüber expands to da + a preposition. Which preposition does 'sich freuen' pair with for current emotions?"},
        {type:"fb",s:"{1} besteht Heinrich? -- Darauf, dass wir Spargel bestellen.",a:["Worauf"],opts:["Worauf","Worüber","Woran","Wofür"],hint:"[AR] Bestehen AUF. The question form uses wo + auf.",sSrc:"[AR] What does Heinrich insist on? -- That we order asparagus."},
        {type:"drag_fill",s:"{1} wir im Biergarten waren, freute sich Hildi {2}. Sie hatte sich lange {3} gefreut.",blanks:{"1":"Als","2":"darüber","3":"darauf"},pool:["Als","Wenn","darüber","darauf","daran","dafür"],hint:"[AR] First: specific past evening (als). Second: happy ABOUT the evening (da + über). Third: had looked FORWARD to it (da + auf).",sSrc:"[AR] When we were in the beer garden, Hildi was happy about it. She had looked forward to it for a long time."},
        {type:"mc",q:"Welcher reflexive Ausdruck beschreibt gesundes, bewusstes Essen, im Gegensatz zum tierischen 'fressen'?",opts:["sich ernähren","fressen","verpflegen","füttern"],ans:"sich ernähren",hint:"[AR] This reflexive verb is about sustained, healthy eating. Not for animals."},
        {type:"match",pairs:[
            {trg:"als",src:"when (one-time past)"},
            {trg:"wenn",src:"when(ever) / if"},
            {trg:"darauf",src:"on it (da + auf)"},
            {trg:"Worauf?",src:"On what? (wo + auf)"}
          ]},
        {type:"mc",q:"Hildi sagt: 'Jedes Mal, _____ die Spargelzeit beginnt, denke ich _____ meine Kindheit.'",opts:["als...über","wenn...auf","als...an","wenn...an"],ans:"wenn...an",hint:"[AR] Every year = repeated (wenn). Thinking OF something = denken AN."},
        {type:"drag_fill",s:"Verumius wartet {1} den Frühling. Er freut sich {2}.",blanks:{"1":"auf","2":"darauf"},pool:["auf","darauf","über","darüber","an","daran"],hint:"[AR] Warten AUF. Then replace 'auf den Frühling' with the da-compound.",sSrc:"[AR] Verumius waits for spring. He looks forward to it."}
      ]}
  ]};

export default UNIT_18_AR;
